export interface SessionData {
  id: string;
  patientName: string;
  date: string;
  notes: string;
  approach: string;
  report?: string;
  isLoading?: boolean;
}

export interface AnalysisRequest {
  notes: string;
  approach: string;
  patientContext?: string;
}

export enum TherapeuticApproach {
  TCC = 'Terapia Cognitivo-Comportamental (TCC)',
  Psicanalise = 'Psicanálise',
  Humanista = 'Humanista',
  Gestalt = 'Gestalt-Terapia',
  Sistemica = 'Sistêmica',
  Integrativa = 'Integrativa'
}

import { GoogleGenAI } from "@google/genai";
import { AnalysisRequest } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
Você é um Assistente Clínico de IA especializado em apoiar psicólogos e terapeutas na organização e análise de sessões. 
Seu objetivo é transformar notas brutas ou transcrições de áudio em relatórios estruturados.

DIRETRIZES ÉTICAS E DE SEGURANÇA (MUITO IMPORTANTE):
1. NUNCA forneça diagnósticos definitivos (CID/DSM). Use termos como "Sugere-se atenção a...", "Padrões observados indicam..." ou "Hipóteses para revisão".
2. Você é uma ferramenta de apoio, não substitui o julgamento clínico.
3. Se detectar menções claras a risco de vida, suicídio ou auto-flagelação, inicie o relatório com um bloco: "🔴 ALERTA CRÍTICO: Risco identificado [detalhes]".
4. Mantenha um tom profissional, técnico, empático e neutro.

TAREFAS DE PROCESSAMENTO:
Gere um relatório seguindo esta estrutura exata em Markdown:

# Relatório de Sessão

## 1. Resumo Executivo
Um parágrafo curto sobre o tema principal.

## 2. Temas Recorrentes
Lista de padrões de pensamento ou comportamento.

## 3. Estado Emocional Observado
Análise do tom (ex: ansioso, depressivo, eufórico).

## 4. Evolução Clínica
Compare com contexto geral ou identifique mudanças de postura.

## 5. Sugestão de Intervenção/Lição de Casa
Sugira atividades baseadas na abordagem teórica solicitada.

## 6. Notas para a Próxima Sessão
Pontos em aberto para exploração futura.
`;

export const analyzeSessionNotes = async (request: AnalysisRequest): Promise<string> => {
  try {
    const prompt = `
      Analise as seguintes anotações da sessão clínica:

      --- INÍCIO DAS NOTAS ---
      ${request.notes}
      --- FIM DAS NOTAS ---

      Abordagem Teórica Desejada: ${request.approach}
      ${request.patientContext ? `Contexto do Paciente: ${request.patientContext}` : ''}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Using Pro for complex reasoning and reasoning capabilities
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.4, // Lower temperature for more consistent, professional output
      },
    });

    return response.text || "Não foi possível gerar o relatório. Tente novamente.";
  } catch (error) {
    console.error("Erro ao analisar sessão:", error);
    return "Erro ao processar a solicitação. Verifique sua conexão ou tente novamente mais tarde.";
  }
};

