import React, { useState } from 'react';
import { TherapeuticApproach } from '../types';
import { Sparkles, FileText, Eraser } from 'lucide-react';

interface InputFormProps {
  onSubmit: (notes: string, approach: string) => void;
  isAnalyzing: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ onSubmit, isAnalyzing }) => {
  const [notes, setNotes] = useState('');
  const [approach, setApproach] = useState<string>(TherapeuticApproach.TCC);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (notes.trim()) {
      onSubmit(notes, approach);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full">
      <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
        <h2 className="font-semibold text-slate-800 flex items-center gap-2">
          <FileText className="h-5 w-5 text-slate-500" />
          Notas da Sessão
        </h2>
        <button 
          onClick={() => setNotes('')}
          className="text-xs text-slate-500 hover:text-red-500 flex items-center gap-1 transition-colors"
          disabled={isAnalyzing}
        >
          <Eraser className="h-3 w-3" /> Limpar
        </button>
      </div>

      <div className="p-5 flex-1 flex flex-col gap-4">
        <div className="flex-1">
          <label htmlFor="notes" className="sr-only">Notas brutas ou transcrição</label>
          <textarea
            id="notes"
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            placeholder="Cole aqui as anotações brutas, transcrição da sessão ou observações soltas..."
            className="w-full h-full min-h-[300px] p-4 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 resize-none text-slate-700 text-base leading-relaxed placeholder-slate-400 outline-none transition-all"
            disabled={isAnalyzing}
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 items-end">
          <div>
            <label htmlFor="approach" className="block text-sm font-medium text-slate-700 mb-1">
              Abordagem Teórica
            </label>
            <div className="relative">
              <select
                id="approach"
                value={approach}
                onChange={(e) => setApproach(e.target.value)}
                className="block w-full pl-3 pr-10 py-2.5 text-base border-slate-300 focus:outline-none focus:ring-teal-500 focus:border-teal-500 sm:text-sm rounded-lg border bg-white shadow-sm"
                disabled={isAnalyzing}
              >
                {Object.values(TherapeuticApproach).map((value) => (
                  <option key={value} value={value}>
                    {value}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <button
            onClick={handleSubmit}
            disabled={!notes.trim() || isAnalyzing}
            className={`flex items-center justify-center w-full py-2.5 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white transition-all
              ${!notes.trim() || isAnalyzing 
                ? 'bg-slate-300 cursor-not-allowed' 
                : 'bg-teal-600 hover:bg-teal-700 hover:shadow-md active:transform active:scale-[0.98]'
              }`}
          >
            {isAnalyzing ? (
              <>
                <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Processando Clínica...
              </>
            ) : (
              <>
                <Sparkles className="h-4 w-4 mr-2" />
                Gerar Relatório Estruturado
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default InputForm;

import React from 'react';
import { Copy, Check, FileCheck, AlertTriangle } from 'lucide-react';

interface ReportViewProps {
  report: string | null;
}

const ReportView: React.FC<ReportViewProps> = ({ report }) => {
  const [copied, setCopied] = React.useState(false);

  const handleCopy = () => {
    if (report) {
      navigator.clipboard.writeText(report);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  if (!report) {
    return (
      <div className="h-full min-h-[400px] flex flex-col items-center justify-center bg-slate-50 rounded-xl border-2 border-dashed border-slate-200 text-slate-400 p-8 text-center">
        <div className="bg-white p-4 rounded-full mb-4 shadow-sm">
          <FileCheck className="h-8 w-8 text-slate-300" />
        </div>
        <h3 className="text-lg font-medium text-slate-600 mb-1">Aguardando Dados</h3>
        <p className="max-w-xs text-sm">
          Insira as notas da sessão ao lado e clique em gerar para visualizar a análise clínica estruturada.
        </p>
      </div>
    );
  }

  // Simple logic to detect critical alerts for visual highlighting
  const hasCriticalAlert = report.includes("🔴 ALERTA CRÍTICO") || report.includes("ALERTA CRÍTICO");

  // Basic formatting to make markdown headers look nicer without a heavy parser library
  const formattedContent = report.split('\n').map((line, index) => {
    if (line.startsWith('# ')) {
      return <h1 key={index} className="text-2xl font-bold text-slate-800 mt-6 mb-4 border-b border-slate-200 pb-2">{line.replace('# ', '')}</h1>;
    }
    if (line.startsWith('## ')) {
      return <h2 key={index} className="text-lg font-bold text-teal-800 mt-6 mb-2 flex items-center">{line.replace('## ', '')}</h2>;
    }
    if (line.startsWith('### ')) {
      return <h3 key={index} className="text-md font-semibold text-slate-700 mt-4 mb-2">{line.replace('### ', '')}</h3>;
    }
    if (line.startsWith('- ') || line.startsWith('* ')) {
      return <li key={index} className="ml-4 mb-1 text-slate-700 list-disc">{line.replace(/^[-*] /, '')}</li>;
    }
    if (line.trim().startsWith('🔴 ALERTA') || line.trim().startsWith('ALERTA CRÍTICO')) {
         return (
             <div key={index} className="bg-red-50 border-l-4 border-red-500 p-4 my-4 rounded-r-lg">
                 <div className="flex items-start">
                     <AlertTriangle className="h-5 w-5 text-red-500 mt-0.5 mr-2 flex-shrink-0" />
                     <p className="text-red-700 font-bold">{line}</p>
                 </div>
             </div>
         )
    }
    if (line.trim() === '') {
      return <div key={index} className="h-2"></div>;
    }
    // Bold formatting for **text**
    const parts = line.split(/(\*\*.*?\*\*)/);
    return (
      <p key={index} className="mb-2 text-slate-600 leading-relaxed">
        {parts.map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
                return <strong key={i} className="text-slate-800 font-semibold">{part.slice(2, -2)}</strong>;
            }
            return part;
        })}
      </p>
    );
  });

  return (
    <div className="bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden flex flex-col h-full relative">
      <div className={`p-4 border-b flex justify-between items-center ${hasCriticalAlert ? 'bg-red-50 border-red-100' : 'bg-slate-50 border-slate-100'}`}>
        <h2 className={`font-semibold flex items-center gap-2 ${hasCriticalAlert ? 'text-red-700' : 'text-slate-800'}`}>
          {hasCriticalAlert ? <AlertTriangle className="h-5 w-5" /> : <FileCheck className="h-5 w-5 text-teal-600" />}
          Relatório Gerado
        </h2>
        <button
          onClick={handleCopy}
          className="text-sm flex items-center gap-1.5 px-3 py-1.5 rounded-md hover:bg-white hover:shadow-sm transition-all text-slate-600 font-medium"
        >
          {copied ? (
            <>
              <Check className="h-4 w-4 text-green-600" />
              <span className="text-green-600">Copiado</span>
            </>
          ) : (
            <>
              <Copy className="h-4 w-4" />
              Copiar
            </>
          )}
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 md:p-8 bg-white">
         <div className="prose prose-slate max-w-none">
            {formattedContent}
         </div>

         <div className="mt-8 pt-6 border-t border-slate-100 text-xs text-slate-400 italic text-center">
            Este relatório foi gerado por IA como suporte. A validação final e assinatura são responsabilidade exclusiva do profissional de saúde.
         </div>
      </div>
    </div>
  );
};

export default ReportView;

import React, { useState } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
import ReportView from './components/ReportView';
import { analyzeSessionNotes } from './services/geminiService';
import { AnalysisRequest } from './types';

function App() {
  const [report, setReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [patientContext, setPatientContext] = useState('');

  const handleAnalysis = async (notes: string, approach: string) => {
    setIsAnalyzing(true);
    setReport(null); // Clear previous report

    const request: AnalysisRequest = {
      notes,
      approach,
      patientContext: patientContext.trim() || undefined
    };

    const result = await analyzeSessionNotes(request);

    setReport(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Intro Section */}
        <div className="mb-8">
          <h2 className="text-2xl font-bold text-slate-900">Novo Relatório Clínico</h2>
          <p className="text-slate-500 mt-1">Transforme anotações de sessão em documentação clínica estruturada.</p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-220px)] min-h-[600px]">
          {/* Left Column: Input */}
          <div className="flex flex-col gap-4 h-full">

            {/* Context (Optional) */}
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                <label className="text-sm font-medium text-slate-700 mb-2 block">Contexto do Paciente (Opcional)</label>
                <input 
                    type="text" 
                    placeholder="Ex: Homem, 35 anos, diagnóstico prévio de TAG..."
                    value={patientContext}
                    onChange={(e) => setPatientContext(e.target.value)}
                    className="w-full text-sm p-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-1 focus:ring-teal-500 outline-none"
                />
            </div>

            {/* Main Input Form */}
            <InputForm onSubmit={handleAnalysis} isAnalyzing={isAnalyzing} />
          </div>

          {/* Right Column: Output */}
          <div className="h-full">
            <ReportView report={report} />
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-sm text-slate-500">
                &copy; {new Date().getFullYear()} PsiAI. Desenvolvido para uso profissional.
                <span className="mx-2 text-slate-300">|</span>
                <span className="text-slate-400">Os dados inseridos são processados em tempo real e não são armazenados permanentemente nesta interface.</span>
            </p>
        </div>
      </footer>
    </div>
  );
}

export default App;

