import React, { useState } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
import ReportView from './components/ReportView';
import TemplateManager from './components/TemplateManager';
import { analyzeSessionNotes } from './services/geminiService';
import { AnalysisRequest, ReportTemplate } from './types';

// Default Templates
const DEFAULT_TEMPLATES: ReportTemplate[] = [
  {
    id: 'default-1',
    name: 'Padrão (Completo)',
    isDefault: true,
    structure: `# Relatório de Sessão

## 1. Resumo Executivo
Um parágrafo curto sobre o tema principal.

## 2. Temas Recorrentes
Lista de padrões de pensamento ou comportamento.

## 3. Estado Emocional Observado
Análise do tom (ex: ansioso, depressivo, eufórico).

## 4. Evolução Clínica
Compare com contexto geral ou identifique mudanças de postura.

## 5. Sugestão de Intervenção/Lição de Casa
Sugira atividades baseadas na abordagem teórica solicitada.

## 6. Notas para a Próxima Sessão
Pontos em aberto para exploração futura.`
  },
  {
    id: 'default-2',
    name: 'SOAP (Clínico)',
    isDefault: true,
    structure: `# Relatório SOAP

## S - Subjetivo (Subjective)
O que o paciente relatou, suas queixas principais e percepções. Use citações se relevante.

## O - Objetivo (Objective)
O que foi observado pelo terapeuta: aparência, afeto, comportamento motor, fala.

## A - Avaliação (Assessment)
Análise clínica, impressões diagnósticas (hipóteses), progresso em relação às metas.

## P - Plano (Plan)
Intervenções realizadas, tarefas de casa passadas e plano para a próxima sessão.`
  },
  {
    id: 'default-3',
    name: 'DAP (Breve)',
    isDefault: true,
    structure: `# Registro DAP

## Dados (Data)
Resumo objetivo do que aconteceu na sessão e o que foi dito.

## Avaliação (Assessment)
Interpretação clínica do terapeuta sobre os dados.

## Plano (Plan)
O que fazer a seguir (próxima consulta, encaminhamentos, tarefas).`
  }
];

function App() {
  const [report, setReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [patientContext, setPatientContext] = useState('');

  // Template State
  const [templates, setTemplates] = useState<ReportTemplate[]>(DEFAULT_TEMPLATES);
  const [selectedTemplateId, setSelectedTemplateId] = useState<string>(DEFAULT_TEMPLATES[0].id);
  const [isTemplateManagerOpen, setIsTemplateManagerOpen] = useState(false);

  const handleAnalysis = async (notes: string, approach: string) => {
    const selectedTemplate = templates.find(t => t.id === selectedTemplateId) || DEFAULT_TEMPLATES[0];

    setIsAnalyzing(true);
    setReport(null); 

    const request: AnalysisRequest = {
      notes,
      approach,
      patientContext: patientContext.trim() || undefined,
      templateStructure: selectedTemplate.structure
    };

    const result = await analyzeSessionNotes(request);

    setReport(result);
    setIsAnalyzing(false);
  };

  const handleAddTemplate = (newTemplate: ReportTemplate) => {
    setTemplates([...templates, newTemplate]);
    setSelectedTemplateId(newTemplate.id); // Auto-select new template
    setIsTemplateManagerOpen(false);
  };

  const handleDeleteTemplate = (id: string) => {
    const newTemplates = templates.filter(t => t.id !== id);
    setTemplates(newTemplates);
    if (selectedTemplateId === id) {
        setSelectedTemplateId(newTemplates[0].id);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Intro Section */}
        <div className="mb-8">
          <h2 className="text-2xl font-bold text-slate-900">Novo Relatório Clínico</h2>
          <p className="text-slate-500 mt-1">Transforme anotações de sessão em documentação clínica estruturada.</p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-220px)] min-h-[600px]">
          {/* Left Column: Input */}
          <div className="flex flex-col gap-4 h-full">

            {/* Context (Optional) */}
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                <label className="text-sm font-medium text-slate-700 mb-2 block">Contexto do Paciente (Opcional)</label>
                <input 
                    type="text" 
                    placeholder="Ex: Homem, 35 anos, diagnóstico prévio de TAG..."
                    value={patientContext}
                    onChange={(e) => setPatientContext(e.target.value)}
                    className="w-full text-sm p-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-1 focus:ring-teal-500 outline-none"
                />
            </div>

            {/* Main Input Form */}
            <InputForm 
                onSubmit={handleAnalysis} 
                isAnalyzing={isAnalyzing} 
                templates={templates}
                selectedTemplateId={selectedTemplateId}
                onSelectTemplate={setSelectedTemplateId}
                onOpenTemplateManager={() => setIsTemplateManagerOpen(true)}
            />
          </div>

          {/* Right Column: Output */}
          <div className="h-full">
            <ReportView report={report} />
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-sm text-slate-500">
                &copy; {new Date().getFullYear()} PsiAI. Desenvolvido para uso profissional.
                <span className="mx-2 text-slate-300">|</span>
                <span className="text-slate-400">Os dados inseridos são processados em tempo real e não são armazenados permanentemente nesta interface.</span>
            </p>
        </div>
      </footer>

      {/* Template Manager Modal */}
      <TemplateManager 
        isOpen={isTemplateManagerOpen}
        onClose={() => setIsTemplateManagerOpen(false)}
        templates={templates}
        onAddTemplate={handleAddTemplate}
        onDeleteTemplate={handleDeleteTemplate}
      />
    </div>
  );
}

export default App;

import React, { useRef, useEffect, useState } from 'react';
import { Bold, Italic, List, ListOrdered } from 'lucide-react';

interface RichTextEditorProps {
  value: string;
  onChange: (value: string) => void;
  disabled?: boolean;
  placeholder?: string;
}

const RichTextEditor: React.FC<RichTextEditorProps> = ({ value, onChange, disabled, placeholder }) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const [isFocused, setIsFocused] = useState(false);

  // Sync with external value changes (e.g. clear form)
  useEffect(() => {
    if (contentRef.current) {
      // Only update if the value is different to avoid cursor jumping
      // This is primarily for when the form is cleared externally
      if (value !== contentRef.current.innerHTML) {
         // If value is empty, clear it specifically
         if (value === '') {
           contentRef.current.innerHTML = '';
         } else if (contentRef.current.innerHTML === '' && value) {
           // Initial load or pasting content programmatically
           contentRef.current.innerHTML = value;
         }
      }
    }
  }, [value]);

  const execCommand = (command: string) => {
    document.execCommand(command, false);
    if (contentRef.current) {
        onChange(contentRef.current.innerHTML);
        contentRef.current.focus();
    }
  };

  const handleToolbarClick = (e: React.MouseEvent, command: string) => {
    e.preventDefault();
    execCommand(command);
  };

  const handleInput = () => {
    if (contentRef.current) {
      const html = contentRef.current.innerHTML;
      // Handle the case where browser leaves <br> in empty editor
      const isEmpty = html === '<br>' || html === '';
      onChange(isEmpty ? '' : html);
    }
  };

  return (
    <div className={`flex flex-col h-full min-h-[300px] border rounded-lg overflow-hidden transition-all bg-white ${isFocused ? 'ring-2 ring-teal-500 border-teal-500' : 'border-slate-200'}`}>
      <div className="flex items-center gap-1 p-2 border-b border-slate-200 bg-slate-50">
        <ToolbarButton 
            onClick={(e) => handleToolbarClick(e, 'bold')} 
            icon={<Bold className="w-4 h-4" />} 
            label="Negrito"
            disabled={disabled}
        />
        <ToolbarButton 
            onClick={(e) => handleToolbarClick(e, 'italic')} 
            icon={<Italic className="w-4 h-4" />} 
            label="Itálico"
            disabled={disabled}
        />
        <div className="w-px h-5 bg-slate-300 mx-1"></div>
        <ToolbarButton 
            onClick={(e) => handleToolbarClick(e, 'insertUnorderedList')} 
            icon={<List className="w-4 h-4" />} 
            label="Lista com marcadores"
            disabled={disabled}
        />
        <ToolbarButton 
            onClick={(e) => handleToolbarClick(e, 'insertOrderedList')} 
            icon={<ListOrdered className="w-4 h-4" />} 
            label="Lista numerada"
            disabled={disabled}
        />
      </div>

      <div 
        className="flex-1 p-4 overflow-y-auto cursor-text text-slate-700 outline-none rich-text-content"
        contentEditable={!disabled}
        ref={contentRef}
        onInput={handleInput}
        onFocus={() => setIsFocused(true)}
        onBlur={() => setIsFocused(false)}
        role="textbox"
        aria-multiline="true"
        aria-placeholder={placeholder}
      />
      <style>{`
        .rich-text-content:empty:before {
          content: attr(aria-placeholder);
          color: #94a3b8;
          pointer-events: none;
          display: block;
        }
        .rich-text-content ul { list-style-type: disc; margin-left: 1.5rem; margin-bottom: 0.5rem; }
        .rich-text-content ol { list-style-type: decimal; margin-left: 1.5rem; margin-bottom: 0.5rem; }
        .rich-text-content li { margin-bottom: 0.25rem; }
        .rich-text-content b, .rich-text-content strong { font-weight: 700; color: #1e293b; }
        .rich-text-content i, .rich-text-content em { font-style: italic; }
        .rich-text-content {
             font-family: 'Inter', sans-serif;
             font-size: 1rem;
             line-height: 1.6;
        }
      `}</style>
    </div>
  );
};

const ToolbarButton: React.FC<{ onClick: (e: React.MouseEvent) => void; icon: React.ReactNode; label: string; disabled?: boolean }> = ({ onClick, icon, label, disabled }) => (
  <button
    type="button"
    onClick={onClick}
    disabled={disabled}
    className="p-2 rounded hover:bg-white hover:shadow-sm text-slate-600 hover:text-teal-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
    title={label}
    onMouseDown={(e) => e.preventDefault()} // Prevent losing focus from editor
  >
    {icon}
  </button>
);

