function App() {
  const [report, setReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [patientContext, setPatientContext] = useState('');

  // Template State
  const [templates, setTemplates] = useState<ReportTemplate[]>(DEFAULT_TEMPLATES);
  const [selectedTemplateId, setSelectedTemplateId] = useState<string>(DEFAULT_TEMPLATES[0].id);
  const [isTemplateManagerOpen, setIsTemplateManagerOpen] = useState(false);

  const handleAnalysis = async (notes: string, approach: string) => {
    const selectedTemplate = templates.find(t => t.id === selectedTemplateId) || DEFAULT_TEMPLATES[0];

    setIsAnalyzing(true);
    setReport(null); 

    const request: AnalysisRequest = {
      notes,
      approach,
      patientContext: patientContext.trim() || undefined,
      templateStructure: selectedTemplate.structure
    };

    const result = await analyzeSessionNotes(request);

    setReport(result);
    setIsAnalyzing(false);
  };

  const handleAddTemplate = (newTemplate: ReportTemplate) => {
    setTemplates([...templates, newTemplate]);
    setSelectedTemplateId(newTemplate.id); // Auto-select new template
    setIsTemplateManagerOpen(false);
  };

  const handleDeleteTemplate = (id: string) => {
    const newTemplates = templates.filter(t => t.id !== id);
    setTemplates(newTemplates);
    if (selectedTemplateId === id) {
        setSelectedTemplateId(newTemplates[0].id);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Intro Section */}
        <div className="mb-8">
          <h2 className="text-2xl font-bold text-slate-900">Novo Relatório Clínico</h2>
          <p className="text-slate-500 mt-1">Transforme anotações de sessão em documentação profissional estruturada.</p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-220px)] min-h-[600px]">
          {/* Left Column: Input */}
          <div className="flex flex-col gap-4 h-full">

            {/* Context (Optional) */}
            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                <label className="text-sm font-medium text-slate-700 mb-2 block">Contexto do Paciente (Opcional)</label>
                <input 
                    type="text" 
                    placeholder="Ex: Homem, 35 anos, diagnóstico de TAG, em luto recente..."
                    value={patientContext}
                    onChange={(e) => setPatientContext(e.target.value)}
                    className="w-full text-sm p-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-1 focus:ring-teal-500 outline-none"
                />
            </div>

            {/* Main Input Form */}
            <InputForm 
                onSubmit={handleAnalysis} 
                isAnalyzing={isAnalyzing} 
                templates={templates}
                selectedTemplateId={selectedTemplateId}
                onSelectTemplate={setSelectedTemplateId}
                onOpenTemplateManager={() => setIsTemplateManagerOpen(true)}
            />
          </div>

          {/* Right Column: Output */}
          <div className="h-full">
            <ReportView report={report} />
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-sm text-slate-500">
                &copy; {new Date().getFullYear()} PsiAI. Desenvolvido para Psicólogos e Terapeutas.
                <span className="mx-2 text-slate-300">|</span>
                <span className="text-slate-400">Dados processados em ambiente seguro.</span>
            </p>
        </div>
      </footer>

      {/* Template Manager Modal */}
      <TemplateManager 
        isOpen={isTemplateManagerOpen}
        onClose={() => setIsTemplateManagerOpen(false)}
        templates={templates}
        onAddTemplate={handleAddTemplate}
        onDeleteTemplate={handleDeleteTemplate}
      />
    </div>
  );
}

