import { Patient, SessionRecord } from '../types';

const PATIENTS_KEY = 'psiai_patients';
const SESSIONS_KEY = 'psiai_sessions';

export const storageService = {
  // Patient Methods
  getPatients: (): Patient[] => {
    const data = localStorage.getItem(PATIENTS_KEY);
    return data ? JSON.parse(data) : [];
  },

  savePatient: (patient: Patient): void => {
    const patients = storageService.getPatients();
    const existingIndex = patients.findIndex(p => p.id === patient.id);

    if (existingIndex >= 0) {
      patients[existingIndex] = patient;
    } else {
      patients.push(patient);
    }

    localStorage.setItem(PATIENTS_KEY, JSON.stringify(patients));
  },

  deletePatient: (id: string): void => {
    const patients = storageService.getPatients().filter(p => p.id !== id);
    localStorage.setItem(PATIENTS_KEY, JSON.stringify(patients));

    // Cleanup sessions for this patient
    const sessions = storageService.getAllSessions().filter(s => s.patientId !== id);
    localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));
  },

  // Session Methods
  getAllSessions: (): SessionRecord[] => {
    const data = localStorage.getItem(SESSIONS_KEY);
    return data ? JSON.parse(data) : [];
  },

  getSessionsByPatient: (patientId: string): SessionRecord[] => {
    const sessions = storageService.getAllSessions();
    return sessions.filter(s => s.patientId === patientId).sort((a, b) => 
      new Date(b.date).getTime() - new Date(a.date).getTime()
    );
  },

  saveSession: (session: SessionRecord): void => {
    const sessions = storageService.getAllSessions();
    sessions.push(session);
    localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));
  },

  deleteSession: (id: string): void => {
    const sessions = storageService.getAllSessions().filter(s => s.id !== id);
    localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));
  }
};

import React, { useState, useEffect } from 'react';
import { Patient, SessionRecord } from '../types';
import { storageService } from '../services/storageService';
import { User, Calendar, FileText, ChevronRight, ChevronDown, Trash2, Search } from 'lucide-react';
import ReportView from './ReportView';

const PatientHistory: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [patientSessions, setPatientSessions] = useState<SessionRecord[]>([]);
  const [selectedSession, setSelectedSession] = useState<SessionRecord | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    loadPatients();
  }, []);

  useEffect(() => {
    if (selectedPatientId) {
      const sessions = storageService.getSessionsByPatient(selectedPatientId);
      setPatientSessions(sessions);
      setSelectedSession(null); // Reset session view when switching patients
    }
  }, [selectedPatientId]);

  const loadPatients = () => {
    setPatients(storageService.getPatients());
  };

  const handleDeletePatient = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('Tem certeza? Isso apagará todo o histórico e relatórios deste paciente.')) {
      storageService.deletePatient(id);
      loadPatients();
      if (selectedPatientId === id) setSelectedPatientId(null);
    }
  };

  const handleDeleteSession = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('Excluir este relatório permanentemente?')) {
      storageService.deleteSession(id);
      if (selectedPatientId) {
        setPatientSessions(storageService.getSessionsByPatient(selectedPatientId));
      }
      if (selectedSession?.id === id) setSelectedSession(null);
    }
  };

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="flex h-[calc(100vh-140px)] bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Sidebar - Patient List */}
      <div className="w-1/3 min-w-[250px] border-r border-slate-200 flex flex-col bg-slate-50">
        <div className="p-4 border-b border-slate-200">
          <h3 className="font-semibold text-slate-800 mb-3 flex items-center gap-2">
            <User className="h-5 w-5 text-teal-600" />
            Pacientes ({patients.length})
          </h3>
          <div className="relative">
            <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Buscar paciente..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-9 pr-4 py-2 text-sm border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto">
          {filteredPatients.length === 0 ? (
            <div className="p-8 text-center text-slate-400 text-sm">
              Nenhum paciente encontrado.
            </div>
          ) : (
            <div className="divide-y divide-slate-100">
              {filteredPatients.map(patient => (
                <div 
                  key={patient.id}
                  onClick={() => setSelectedPatientId(patient.id)}
                  className={`p-4 cursor-pointer hover:bg-white transition-colors group ${selectedPatientId === patient.id ? 'bg-white border-l-4 border-teal-500 shadow-sm' : 'border-l-4 border-transparent'}`}
                >
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className={`font-medium ${selectedPatientId === patient.id ? 'text-teal-800' : 'text-slate-700'}`}>
                        {patient.name}
                      </h4>
                      <p className="text-xs text-slate-500 mt-1 line-clamp-1">{patient.context}</p>
                    </div>
                    <button 
                      onClick={(e) => handleDeletePatient(e, patient.id)}
                      className="opacity-0 group-hover:opacity-100 text-slate-400 hover:text-red-500 p-1"
                      title="Excluir Paciente"
                    >
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Main Content - Sessions List or Report View */}
      <div className="flex-1 flex flex-col bg-slate-50/50">
        {!selectedPatientId ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <User className="h-12 w-12 mb-3 opacity-20" />
            <p>Selecione um paciente para ver o histórico</p>
          </div>
        ) : (
          <div className="flex h-full">
            {/* Session List Column */}
            <div className={`${selectedSession ? 'w-1/3 hidden lg:block' : 'w-full'} border-r border-slate-200 overflow-y-auto bg-white`}>
              <div className="p-4 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
                <h4 className="font-semibold text-slate-700">Histórico de Sessões</h4>
                <span className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded-full">{patientSessions.length}</span>
              </div>

              {patientSessions.length === 0 ? (
                <div className="p-8 text-center text-slate-400 text-sm">
                  Nenhuma sessão registrada para este paciente.
                </div>
              ) : (
                <div className="p-3 space-y-3">
                  {patientSessions.map(session => (
                    <div 
                      key={session.id}
                      onClick={() => setSelectedSession(session)}
                      className={`p-4 rounded-lg border cursor-pointer transition-all hover:shadow-md ${selectedSession?.id === session.id ? 'border-teal-500 bg-teal-50 ring-1 ring-teal-500' : 'border-slate-200 bg-white'}`}
                    >
                      <div className="flex justify-between items-start mb-2">
                        <div className="flex items-center gap-2 text-sm font-medium text-slate-800">
                          <Calendar className="h-3.5 w-3.5 text-teal-600" />
                          {new Date(session.date).toLocaleDateString()}
                        </div>
                        <button 
                           onClick={(e) => handleDeleteSession(e, session.id)}
                           className="text-slate-300 hover:text-red-500"
                        >
                           <Trash2 className="h-3.5 w-3.5" />
                        </button>
                      </div>
                      <div className="flex items-center gap-1.5 mb-2">
                         <span className="text-[10px] uppercase font-bold text-slate-500 bg-slate-100 px-1.5 py-0.5 rounded">
                           {session.approach.split(' ')[0]}
                         </span>
                      </div>
                      <p className="text-xs text-slate-500 line-clamp-2 italic">
                        "{session.rawNotes.replace(/<[^>]*>?/gm, '').substring(0, 100)}..."
                      </p>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Report Detail View */}
            {selectedSession && (
              <div className="flex-1 overflow-y-auto p-4 lg:p-6 bg-slate-50">
                 <div className="mb-4 flex items-center justify-between lg:hidden">
                    <button onClick={() => setSelectedSession(null)} className="text-sm text-teal-600 font-medium flex items-center">
                        <ChevronDown className="h-4 w-4 rotate-90 mr-1" /> Voltar para lista
                    </button>
                 </div>
                 <ReportView report={selectedSession.generatedReport} />
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

