  }, []);

  const refreshPatients = () => {
    setPatients(storageService.getPatients());
  };

  const handleCreatePatient = () => {
    if (!newPatientName.trim()) return;

    const newPatient: Patient = {
        id: Date.now().toString(),
        name: newPatientName,
        context: newPatientContext,
        createdAt: new Date().toISOString()
    };

    storageService.savePatient(newPatient);
    refreshPatients();
    setCurrentPatient(newPatient);
    setIsCreatingPatient(false);
    setNewPatientName('');
    setNewPatientContext('');
  };

  const handleAnalysis = async (notes: string, approach: string) => {
    const selectedTemplate = templates.find(t => t.id === selectedTemplateId) || DEFAULT_TEMPLATES[0];

    setIsAnalyzing(true);
    setReport(null); 

    const request: AnalysisRequest = {
      notes,
      approach,
      patientContext: currentPatient?.context,
      templateStructure: selectedTemplate.structure
    };

    const result = await analyzeSessionNotes(request);
    setReport(result);
    setIsAnalyzing(false);

    // Auto-save session if patient is selected
    if (currentPatient && result) {
        const newSession: SessionRecord = {
            id: Date.now().toString(),
            patientId: currentPatient.id,
            date: new Date().toISOString(),
            rawNotes: notes,
            generatedReport: result,
            approach,
            templateName: selectedTemplate.name
        };
        storageService.saveSession(newSession);
    }
  };

  const handleAddTemplate = (newTemplate: ReportTemplate) => {
    setTemplates([...templates, newTemplate]);
    setSelectedTemplateId(newTemplate.id);
    setIsTemplateManagerOpen(false);
  };

  const handleDeleteTemplate = (id: string) => {
    const newTemplates = templates.filter(t => t.id !== id);
    setTemplates(newTemplates);
    if (selectedTemplateId === id) {
        setSelectedTemplateId(newTemplates[0].id);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-6">

        {/* Navigation Tabs */}
        <div className="flex items-center space-x-4 mb-6 border-b border-slate-200">
            <button
                onClick={() => setActiveTab('new')}
                className={`pb-3 px-1 flex items-center gap-2 text-sm font-medium border-b-2 transition-colors ${activeTab === 'new' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
                <Plus className="h-4 w-4" /> Nova Sessão
            </button>
            <button
                onClick={() => setActiveTab('history')}
                className={`pb-3 px-1 flex items-center gap-2 text-sm font-medium border-b-2 transition-colors ${activeTab === 'history' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
                <History className="h-4 w-4" /> Histórico de Pacientes
            </button>
        </div>

        {activeTab === 'new' ? (
            <>
                {/* Patient Selection Section */}
                <div className="mb-6 bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="flex items-center justify-between mb-2">
                        <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
                            <Users className="h-4 w-4 text-teal-600" />
                            Paciente
                        </label>
                        {!isCreatingPatient && (
                            <button 
                                onClick={() => setIsCreatingPatient(true)}
                                className="text-xs text-teal-600 font-bold hover:text-teal-800 uppercase tracking-wide flex items-center gap-1"
                            >
                                <Plus className="h-3 w-3" /> Novo Paciente
                            </button>
                        )}
                    </div>

                    {isCreatingPatient ? (
                        <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 animate-fadeIn">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                                <div>
                                    <label className="block text-xs font-medium text-slate-500 mb-1">Nome Completo</label>
                                    <input 
                                        type="text"
                                        value={newPatientName}
                                        onChange={(e) => setNewPatientName(e.target.value)}
                                        className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                        placeholder="Nome do paciente"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-slate-500 mb-1">Contexto / Anamnese Resumida</label>
                                    <input 
                                        type="text"
                                        value={newPatientContext}
                                        onChange={(e) => setNewPatientContext(e.target.value)}
                                        className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                        placeholder="Ex: 35 anos, diagnóstico de TAG..."
                                    />
                                </div>
                            </div>
                            <div className="flex justify-end gap-2">
                                <button 
                                    onClick={() => setIsCreatingPatient(false)}
                                    className="px-3 py-1.5 text-xs font-medium text-slate-600 hover:text-slate-800"
                                >
                                    Cancelar
                                </button>
                                <button 
                                    onClick={handleCreatePatient}
                                    disabled={!newPatientName.trim()}
                                    className="px-3 py-1.5 text-xs font-medium bg-teal-600 text-white rounded-md hover:bg-teal-700 disabled:opacity-50"
                                >
                                    Salvar Paciente
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="relative">
                            <select
                                value={currentPatient?.id || ''}
                                onChange={(e) => {
                                    const p = patients.find(pat => pat.id === e.target.value);
                                    setCurrentPatient(p || null);
                                }}
                                className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-800 focus:ring-1 focus:ring-teal-500 outline-none"
                            >
                                <option value="">Selecione um paciente para vincular ao relatório...</option>
                                {patients.map(p => (
                                    <option key={p.id} value={p.id}>{p.name}</option>
                                ))}
                            </select>
                            {currentPatient && (
                                <p className="mt-2 text-xs text-slate-500 bg-slate-50 p-2 rounded border border-slate-100 italic">
                                    <span className="font-semibold not-italic text-slate-600">Contexto:</span> {currentPatient.context || "Sem contexto definido."}
                                </p>
                            )}
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-280px)] min-h-[600px]">
                    {/* Left Column: Input */}
                    <div className="flex flex-col gap-4 h-full">
                        <InputForm 
                            onSubmit={handleAnalysis} 
                            isAnalyzing={isAnalyzing} 
                            templates={templates}
                            selectedTemplateId={selectedTemplateId}
                            onSelectTemplate={setSelectedTemplateId}
                            onOpenTemplateManager={() => setIsTemplateManagerOpen(true)}
                        />
                    </div>

                    {/* Right Column: Output */}
                    <div className="h-full relative">
                        <ReportView report={report} />
                        {report && currentPatient && !isAnalyzing && (
                            <div className="absolute top-4 right-20 bg-teal-100 text-teal-800 text-xs px-2 py-1 rounded-md flex items-center gap-1 animate-pulse">
                                <Save className="h-3 w-3" /> Salvo no Histórico
                            </div>
                        )}
                        {report && !currentPatient && !isAnalyzing && (
                            <div className="absolute top-4 right-20 bg-yellow-100 text-yellow-800 text-xs px-2 py-1 rounded-md flex items-center gap-1">
                                ⚠️ Não salvo (Sem Paciente)
                            </div>
                        )}
                    </div>
                </div>
            </>
        ) : (
            <PatientHistory />
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-sm text-slate-500">
                &copy; {new Date().getFullYear()} PsiAI. Desenvolvido para Psicólogos e Terapeutas.
                <span className="mx-2 text-slate-300">|</span>
                <span className="text-slate-400">Dados armazenados localmente no seu dispositivo.</span>
            </p>
        </div>
      </footer>

      <TemplateManager 
        isOpen={isTemplateManagerOpen}
        onClose={() => setIsTemplateManagerOpen(false)}
        templates={templates}
        onAddTemplate={handleAddTemplate}
        onDeleteTemplate={handleDeleteTemplate}
      />
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Patient, SessionRecord } from '../types';
import { storageService } from '../services/storageService';
import { User, Calendar, ChevronDown, Trash2, Search, ArrowLeft, FileText } from 'lucide-react';
import ReportView from './ReportView';

const PatientHistory: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [patientSessions, setPatientSessions] = useState<SessionRecord[]>([]);
  const [selectedSession, setSelectedSession] = useState<SessionRecord | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    loadPatients();
  }, []);

  useEffect(() => {
    if (selectedPatientId) {
      const sessions = storageService.getSessionsByPatient(selectedPatientId);
      setPatientSessions(sessions);
      setSelectedSession(null); 
    }
  }, [selectedPatientId]);

  const loadPatients = () => {
    setPatients(storageService.getPatients());
  };

  const handleDeletePatient = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('Tem certeza? Isso apagará todo o histórico e relatórios deste paciente.')) {
      storageService.deletePatient(id);
      loadPatients();
      if (selectedPatientId === id) setSelectedPatientId(null);
    }
  };

  const handleDeleteSession = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('Excluir este relatório permanentemente?')) {
      storageService.deleteSession(id);
      if (selectedPatientId) {
        setPatientSessions(storageService.getSessionsByPatient(selectedPatientId));
      }
      if (selectedSession?.id === id) setSelectedSession(null);
    }
  };

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const selectedPatient = patients.find(p => p.id === selectedPatientId);

  return (
    <div className="flex flex-col md:flex-row h-[calc(100vh-180px)] md:h-[calc(100vh-140px)] bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden relative">

      {/* Sidebar - Patient List */}
      {/* Mobile: Hidden if patient selected. Desktop: Always visible (1/3 width) */}
      <div className={`
        flex-col bg-slate-50 border-r border-slate-200
        ${selectedPatientId ? 'hidden md:flex' : 'flex w-full'}
        md:w-1/3 md:min-w-[250px]
      `}>
        <div className="p-4 border-b border-slate-200">
          <h3 className="font-semibold text-slate-800 mb-3 flex items-center gap-2">
            <User className="h-5 w-5 text-teal-600" />
            Pacientes ({patients.length})
          </h3>
          <div className="relative">
            <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Buscar paciente..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-9 pr-4 py-2 text-sm border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto">
          {filteredPatients.length === 0 ? (
            <div className="p-8 text-center text-slate-400 text-sm">
              Nenhum paciente encontrado.
            </div>
          ) : (
            <div className="divide-y divide-slate-100">
              {filteredPatients.map(patient => (
                <div 
                  key={patient.id}
                  onClick={() => setSelectedPatientId(patient.id)}
                  className={`p-4 cursor-pointer hover:bg-white transition-colors group ${selectedPatientId === patient.id ? 'bg-white border-l-4 border-teal-500 shadow-sm' : 'border-l-4 border-transparent'}`}
                >
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className={`font-medium ${selectedPatientId === patient.id ? 'text-teal-800' : 'text-slate-700'}`}>
                        {patient.name}
                      </h4>
                      <p className="text-xs text-slate-500 mt-1 line-clamp-1">{patient.context}</p>
                    </div>
                    <button 
                      onClick={(e) => handleDeletePatient(e, patient.id)}
                      className="opacity-100 md:opacity-0 md:group-hover:opacity-100 text-slate-300 hover:text-red-500 p-2"
                      title="Excluir Paciente"
                    >
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Main Content Area */}
      {/* Mobile: Visible only if patient selected. Desktop: Always visible (2/3 width) */}
      <div className={`
        flex-1 flex-col bg-slate-50/50
        ${selectedPatientId ? 'flex' : 'hidden md:flex'}
      `}>
        {!selectedPatientId ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400 p-8 text-center">
            <User className="h-12 w-12 mb-3 opacity-20" />
            <p>Selecione um paciente para ver o histórico</p>
          </div>
        ) : (
          <div className="flex flex-col lg:flex-row h-full">

            {/* Session List Column */}
            {/* Mobile: Hidden if session selected (viewing report). Desktop: Always visible (1/3 of content) */}
            <div className={`
               flex-col border-r border-slate-200 overflow-y-auto bg-white
               ${selectedSession ? 'hidden lg:flex' : 'flex w-full'}
               lg:w-1/3 lg:min-w-[280px]
            `}>
              <div className="p-4 border-b border-slate-100 sticky top-0 bg-white z-10">
                {/* Mobile Back Button */}
                <button 
                    onClick={() => setSelectedPatientId(null)}
                    className="md:hidden flex items-center text-slate-500 hover:text-teal-600 mb-3 text-sm font-medium transition-colors"
                >
                    <ArrowLeft className="h-4 w-4 mr-1" /> Voltar para Pacientes
                </button>

                <div className="flex justify-between items-center">
                    <div>
                        <h4 className="font-semibold text-slate-800">{selectedPatient?.name}</h4>
                        <p className="text-xs text-slate-500">Histórico de Sessões</p>
                    </div>
                    <span className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded-full font-medium">{patientSessions.length}</span>
                </div>
              </div>

              {patientSessions.length === 0 ? (
                <div className="p-8 text-center text-slate-400 text-sm">
                  Nenhuma sessão registrada.
                </div>
