      <footer className="bg-white border-t border-slate-200 py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-xs md:text-sm text-slate-500">
                &copy; {new Date().getFullYear()} PsiAI. Desenvolvido para Psicólogos e Terapeutas.
                <span className="block md:inline mx-0 md:mx-2 mt-1 md:mt-0 text-slate-300">|</span>
                <span className="text-slate-400 block md:inline">Dados armazenados localmente no seu dispositivo.</span>
