import { Patient, SessionRecord, ScheduledSession } from '../types';

const PATIENTS_KEY = 'psiai_patients';
const SESSIONS_KEY = 'psiai_sessions';
const SCHEDULE_KEY = 'psiai_schedule';

export const storageService = {
  // Patient Methods
  getPatients: (): Patient[] => {
    const data = localStorage.getItem(PATIENTS_KEY);
    return data ? JSON.parse(data) : [];
  },

  savePatient: (patient: Patient): void => {
    const patients = storageService.getPatients();
    const existingIndex = patients.findIndex(p => p.id === patient.id);

    if (existingIndex >= 0) {
      patients[existingIndex] = patient;
    } else {
      patients.push(patient);
    }

    localStorage.setItem(PATIENTS_KEY, JSON.stringify(patients));
  },

  deletePatient: (id: string): void => {
    const patients = storageService.getPatients().filter(p => p.id !== id);
    localStorage.setItem(PATIENTS_KEY, JSON.stringify(patients));

    // Cleanup sessions for this patient
    const sessions = storageService.getAllSessions().filter(s => s.patientId !== id);
    localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));

    // Cleanup schedule for this patient
    const schedule = storageService.getScheduledSessions().filter(s => s.patientId !== id);
    localStorage.setItem(SCHEDULE_KEY, JSON.stringify(schedule));
  },

  // Session Methods
  getAllSessions: (): SessionRecord[] => {
    const data = localStorage.getItem(SESSIONS_KEY);
    return data ? JSON.parse(data) : [];
  },

  getSessionsByPatient: (patientId: string): SessionRecord[] => {
    const sessions = storageService.getAllSessions();
    return sessions.filter(s => s.patientId === patientId).sort((a, b) => 
      new Date(b.date).getTime() - new Date(a.date).getTime()
    );
  },

  saveSession: (session: SessionRecord): void => {
    const sessions = storageService.getAllSessions();
    sessions.push(session);
    localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));
  },

  deleteSession: (id: string): void => {
    const sessions = storageService.getAllSessions().filter(s => s.id !== id);
    localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));
  },

  // Schedule Methods
  getScheduledSessions: (): ScheduledSession[] => {
    const data = localStorage.getItem(SCHEDULE_KEY);
    return data ? JSON.parse(data) : [];
  },

  saveScheduledSession: (session: ScheduledSession): void => {
    const schedule = storageService.getScheduledSessions();
    const existingIndex = schedule.findIndex(s => s.id === session.id);

    if (existingIndex >= 0) {
      schedule[existingIndex] = session;
    } else {
      schedule.push(session);
    }

    localStorage.setItem(SCHEDULE_KEY, JSON.stringify(schedule));
  },

  updateScheduledSessionStatus: (id: string, status: ScheduledSession['status']): void => {
    const schedule = storageService.getScheduledSessions();
    const session = schedule.find(s => s.id === id);
    if (session) {
      session.status = status;
      localStorage.setItem(SCHEDULE_KEY, JSON.stringify(schedule));
    }
  },

  deleteScheduledSession: (id: string): void => {
    const schedule = storageService.getScheduledSessions().filter(s => s.id !== id);
    localStorage.setItem(SCHEDULE_KEY, JSON.stringify(schedule));
  }
};

import React, { useState, useEffect } from 'react';
import { Patient, ScheduledSession } from '../types';
import { storageService } from '../services/storageService';
import { Calendar, Clock, Plus, CheckCircle, XCircle, Trash2, User, Play, X } from 'lucide-react';

interface ScheduledSessionsProps {
  onStartSession: (patientId: string) => void;
}

const ScheduledSessions: React.FC<ScheduledSessionsProps> = ({ onStartSession }) => {
  const [sessions, setSessions] = useState<ScheduledSession[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form State
  const [selectedPatientId, setSelectedPatientId] = useState('');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [duration, setDuration] = useState(50);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = () => {
    setPatients(storageService.getPatients());
    // Sort sessions: Upcoming first, then by date/time
    const loadedSessions = storageService.getScheduledSessions().sort((a, b) => {
      const dateA = new Date(`${a.date}T${a.time}`);
      const dateB = new Date(`${b.date}T${b.time}`);
      return dateA.getTime() - dateB.getTime();
    });
    setSessions(loadedSessions);
  };

  const handleSave = () => {
    if (!selectedPatientId || !date || !time) return;

    const newSession: ScheduledSession = {
      id: Date.now().toString(),
      patientId: selectedPatientId,
      date,
      time,
      duration,
      status: 'scheduled'
    };

    storageService.saveScheduledSession(newSession);
    loadData();
    setIsModalOpen(false);
    resetForm();
  };

  const resetForm = () => {
    setSelectedPatientId('');
    setDate('');
    setTime('');
    setDuration(50);
  };

  const updateStatus = (id: string, status: ScheduledSession['status']) => {
    storageService.updateScheduledSessionStatus(id, status);
    loadData();
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Cancelar este agendamento?')) {
      storageService.deleteScheduledSession(id);
      loadData();
    }
  };

  const getPatientName = (id: string) => {
    return patients.find(p => p.id === id)?.name || 'Paciente Desconhecido';
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'bg-green-100 text-green-800 border-green-200';
      case 'cancelled': return 'bg-red-100 text-red-800 border-red-200';
      default: return 'bg-white text-slate-800 border-slate-200';
    }
  };

  const filterSessions = (status: string) => {
      return sessions.filter(s => {
          if (status === 'upcoming') return s.status === 'scheduled';
          return s.status === status;
      });
  };

  return (
    <div className="h-full flex flex-col">
      {/* Header / Actions */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
           <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
             <Calendar className="h-6 w-6 text-teal-600" />
             Agenda
           </h2>
           <p className="text-sm text-slate-500">Gerencie seus próximos atendimentos.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-teal-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-teal-700 transition-colors flex items-center gap-2 shadow-sm"
        >
          <Plus className="h-4 w-4" /> Novo Agendamento
        </button>
      </div>

      {/* Lists */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Scheduled / Upcoming */}
        <div className="lg:col-span-2 space-y-4">
            <h3 className="font-semibold text-slate-700 flex items-center gap-2 border-b border-slate-200 pb-2">
                <Clock className="h-4 w-4 text-teal-600" /> Próximas Sessões
            </h3>

            {filterSessions('upcoming').length === 0 ? (
                <div className="bg-slate-50 border border-dashed border-slate-200 rounded-lg p-8 text-center text-slate-400">
                    Nenhuma sessão agendada.
                </div>
            ) : (
                <div className="grid gap-3">
                    {filterSessions('upcoming').map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-4 transition-all hover:shadow-md">
                            <div className="flex items-start gap-3">
                                <div className="bg-teal-50 p-2.5 rounded-full mt-1">
                                    <User className="h-5 w-5 text-teal-600" />
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-800">{getPatientName(session.patientId)}</h4>
                                    <div className="flex items-center gap-3 text-sm text-slate-500 mt-1">
                                        <span className="flex items-center gap-1">
                                            <Calendar className="h-3.5 w-3.5" /> 
                                            {new Date(session.date).toLocaleDateString()}
                                        </span>
                                        <span className="flex items-center gap-1">
                                            <Clock className="h-3.5 w-3.5" /> 
                                            {session.time} ({session.duration} min)
                                        </span>
                                    </div>
                                </div>
                            </div>

                            <div className="flex items-center gap-2 w-full md:w-auto">
                                <button 
                                    onClick={() => {
                                        updateStatus(session.id, 'completed');
                                        onStartSession(session.patientId);
                                    }}
                                    className="flex-1 md:flex-none flex items-center justify-center gap-1 bg-teal-600 text-white px-3 py-1.5 rounded-md text-xs font-medium hover:bg-teal-700 transition-colors"
                                    title="Iniciar Atendimento"
                                >
                                    <Play className="h-3 w-3" /> Iniciar
                                </button>
                                <button 
                                    onClick={() => updateStatus(session.id, 'cancelled')}
                                    className="p-1.5 text-slate-400 hover:text-red-500 border border-slate-200 rounded hover:bg-red-50 transition-colors"
                                    title="Cancelar"
                                >
                                    <XCircle className="h-4 w-4" />
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>

        {/* Recent History (Completed/Cancelled) */}
        <div className="space-y-4">
             <h3 className="font-semibold text-slate-700 flex items-center gap-2 border-b border-slate-200 pb-2">
                <Calendar className="h-4 w-4 text-slate-400" /> Recentes
            </h3>
            <div className="space-y-2">
                {sessions.filter(s => s.status !== 'scheduled').sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 10).map(session => (
                    <div key={session.id} className={`p-3 rounded-lg border text-sm flex justify-between items-center ${getStatusColor(session.status)}`}>
                        <div>
                            <p className="font-medium">{getPatientName(session.patientId)}</p>
                            <p className="text-xs opacity-80">{new Date(session.date).toLocaleDateString()} às {session.time}</p>
                        </div>
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] uppercase font-bold tracking-wider px-1.5 py-0.5 rounded bg-white/50">
                                {session.status === 'completed' ? 'Realizada' : 'Cancelada'}
                            </span>
                            <button onClick={() => handleDelete(session.id)} className="text-slate-400 hover:text-red-600">
                                <Trash2 className="h-3.5 w-3.5" />
                            </button>
                        </div>
                    </div>
                ))}
                {sessions.filter(s => s.status !== 'scheduled').length === 0 && (
                    <p className="text-xs text-slate-400 italic text-center py-4">Nenhum histórico recente.</p>
                )}
            </div>
        </div>

      </div>

      {/* Modal Create */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
           <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm" onClick={() => setIsModalOpen(false)}></div>
           <div className="bg-white rounded-xl shadow-xl w-full max-w-md z-10 overflow-hidden animate-fadeIn">
              <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                  <h3 className="font-bold text-slate-800">Novo Agendamento</h3>
                  <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600"><X className="h-5 w-5"/></button>
              </div>
              <div className="p-6 space-y-4">
                  <div>
                      <label className="block text-xs font-medium text-slate-600 mb-1">Paciente</label>
                      <select 
                        value={selectedPatientId} 
                        onChange={(e) => setSelectedPatientId(e.target.value)}
                        className="w-full p-2.5 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                      >
                          <option value="">Selecione...</option>
                          {patients.map(p => (
                              <option key={p.id} value={p.id}>{p.name}</option>
                          ))}
                      </select>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                      <div>
                          <label className="block text-xs font-medium text-slate-600 mb-1">Data</label>
                          <input 
                            type="date" 
                            value={date}
                            onChange={(e) => setDate(e.target.value)}
                            className="w-full p-2.5 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                          />
                      </div>
                      <div>
                          <label className="block text-xs font-medium text-slate-600 mb-1">Horário</label>
                          <input 
                            type="time" 
                            value={time}
                            onChange={(e) => setTime(e.target.value)}
                            className="w-full p-2.5 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                          />
                      </div>
                  </div>
                  <div>
                      <label className="block text-xs font-medium text-slate-600 mb-1">Duração (minutos)</label>
                      <input 
                        type="number" 
                        value={duration}
                        onChange={(e) => setDuration(Number(e.target.value))}
                        className="w-full p-2.5 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                      />
                  </div>

                  <button 
                    onClick={handleSave}
                    disabled={!selectedPatientId || !date || !time}
                    className="w-full mt-4 bg-teal-600 text-white py-2.5 rounded-lg font-medium hover:bg-teal-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                  >
                      Confirmar Agendamento
                  </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

