import { Plus, Users, History, Save, Calculator, Calendar as CalendarIcon, Ruler, Weight, CalendarCheck, Phone } from 'lucide-react';

// Default Templates
const DEFAULT_TEMPLATES: ReportTemplate[] = [
  {
    id: 'default-1',
    name: 'Padrão (Evolução Clínica)',
    isDefault: true,
    structure: `# Evolução Clínica

