type Tab = 'new' | 'history' | 'schedule';

function App() {
  const [activeTab, setActiveTab] = useState<Tab>('new');
  const [report, setReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Patient State
  const [patients, setPatients] = useState<Patient[]>([]);
  const [currentPatient, setCurrentPatient] = useState<Patient | null>(null);
  const [isCreatingPatient, setIsCreatingPatient] = useState(false);

  // New Patient Form State
  const [newPatientName, setNewPatientName] = useState('');
  const [newPatientPhone, setNewPatientPhone] = useState('');
  const [newPatientBirthDate, setNewPatientBirthDate] = useState('');
  const [newPatientAge, setNewPatientAge] = useState('');
  const [newPatientHeight, setNewPatientHeight] = useState('');
  const [newPatientWeight, setNewPatientWeight] = useState('');
  const [newPatientContext, setNewPatientContext] = useState('');

  // Template State
  const [templates, setTemplates] = useState<ReportTemplate[]>(DEFAULT_TEMPLATES);
  const [selectedTemplateId, setSelectedTemplateId] = useState<string>(DEFAULT_TEMPLATES[0].id);
  const [isTemplateManagerOpen, setIsTemplateManagerOpen] = useState(false);

  useEffect(() => {
    refreshPatients();

    // Check for reminders immediately on load
    notificationService.checkAndSendReminders();

    // Check every minute
    const interval = setInterval(() => {
        notificationService.checkAndSendReminders();
    }, 60000);

    return () => clearInterval(interval);
  }, []);

  const refreshPatients = () => {
    setPatients(storageService.getPatients());
  };

  const calculateAge = (dob: string) => {
    if (!dob) return;
    const birthDate = new Date(dob);
    const today = new Date();
    let age = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
      age--;
    }
    setNewPatientAge(age.toString());
  };

  const handleCreatePatient = () => {
    if (!newPatientName.trim()) return;

    const newPatient: Patient = {
        id: Date.now().toString(),
        name: newPatientName,
        phoneNumber: newPatientPhone,
        birthDate: newPatientBirthDate,
        age: newPatientAge,
        height: newPatientHeight,
        weight: newPatientWeight,
        context: newPatientContext,
        createdAt: new Date().toISOString()
    };

    storageService.savePatient(newPatient);
    refreshPatients();
    setCurrentPatient(newPatient);
    setIsCreatingPatient(false);

    // Reset form
    setNewPatientName('');
    setNewPatientPhone('');
    setNewPatientBirthDate('');
    setNewPatientAge('');
    setNewPatientHeight('');
    setNewPatientWeight('');
    setNewPatientContext('');
  };

  const handleAnalysis = async (notes: string, approach: string) => {
    const selectedTemplate = templates.find(t => t.id === selectedTemplateId) || DEFAULT_TEMPLATES[0];

    setIsAnalyzing(true);
    setReport(null); 

    // Construct a rich context string including demographics
    let fullContext = currentPatient?.context || "";
    if (currentPatient) {
        const demos = [];
        if (currentPatient.age) demos.push(`Idade: ${currentPatient.age} anos`);
        if (currentPatient.birthDate) demos.push(`Data de Nasc.: ${new Date(currentPatient.birthDate).toLocaleDateString('pt-BR')}`);
        if (currentPatient.height) demos.push(`Altura: ${currentPatient.height}cm`);
        if (currentPatient.weight) demos.push(`Peso: ${currentPatient.weight}kg`);

        if (demos.length > 0) {
            fullContext = `DADOS DEMOGRÁFICOS:\n${demos.join(' | ')}\n\nCONTEXTO CLÍNICO:\n${fullContext}`;
        }
    }

    const request: AnalysisRequest = {
      notes,
      approach,
      patientContext: fullContext,
      templateStructure: selectedTemplate.structure
    };

    const result = await analyzeSessionNotes(request);
    setReport(result);
    setIsAnalyzing(false);

    // Auto-save session if patient is selected
    if (currentPatient && result) {
        const newSession: SessionRecord = {
            id: Date.now().toString(),
            patientId: currentPatient.id,
            date: new Date().toISOString(),
            rawNotes: notes,
            generatedReport: result,
            approach,
            templateName: selectedTemplate.name
        };
        storageService.saveSession(newSession);
    }
  };

  const handleStartScheduledSession = (patientId: string) => {
      const patient = patients.find(p => p.id === patientId);
      if (patient) {
          setCurrentPatient(patient);
          setActiveTab('new');
      }
  };

  const handleAddTemplate = (newTemplate: ReportTemplate) => {
    setTemplates([...templates, newTemplate]);
    setSelectedTemplateId(newTemplate.id);
    setIsTemplateManagerOpen(false);
  };

  const handleDeleteTemplate = (id: string) => {
    const newTemplates = templates.filter(t => t.id !== id);
    setTemplates(newTemplates);
    if (selectedTemplateId === id) {
        setSelectedTemplateId(newTemplates[0].id);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <Header />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-4 md:py-8">

        {/* Navigation Tabs */}
        <div className="flex items-center space-x-4 mb-6 border-b border-slate-200 overflow-x-auto">
            <button
                onClick={() => setActiveTab('new')}
                className={`pb-3 px-1 flex items-center gap-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${activeTab === 'new' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
                <Plus className="h-4 w-4" /> Nova Sessão
            </button>
            <button
                onClick={() => setActiveTab('schedule')}
                className={`pb-3 px-1 flex items-center gap-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${activeTab === 'schedule' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
                <CalendarCheck className="h-4 w-4" /> Sessões Agendadas
            </button>
            <button
                onClick={() => setActiveTab('history')}
                className={`pb-3 px-1 flex items-center gap-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${activeTab === 'history' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
                <History className="h-4 w-4" /> Histórico de Pacientes
            </button>
        </div>

        {activeTab === 'new' && (
            <>
                {/* Patient Selection Section */}
                <div className="mb-6 bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="flex flex-wrap items-center justify-between mb-2 gap-2">
                        <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
                            <Users className="h-4 w-4 text-teal-600" />
                            Paciente
                        </label>
                        {!isCreatingPatient && (
                            <button 
                                onClick={() => setIsCreatingPatient(true)}
                                className="text-xs text-teal-600 font-bold hover:text-teal-800 uppercase tracking-wide flex items-center gap-1 bg-teal-50 px-2 py-1 rounded"
                            >
                                <Plus className="h-3 w-3" /> Novo Paciente
                            </button>
                        )}
                    </div>

                    {isCreatingPatient ? (
                        <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 animate-fadeIn mt-2">
                            <div className="space-y-4 mb-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Nome Completo *</label>
                                        <input 
                                            type="text"
                                            value={newPatientName}
                                            onChange={(e) => setNewPatientName(e.target.value)}
                                            className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                            placeholder="Nome do paciente"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">WhatsApp / Telefone</label>
                                        <input 
                                            type="text"
                                            value={newPatientPhone}
                                            onChange={(e) => setNewPatientPhone(e.target.value)}
                                            className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                            placeholder="Ex: 11 99999-9999"
                                        />
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Data de Nascimento</label>
                                        <div className="relative">
                                            <input 
                                                type="date"
                                                value={newPatientBirthDate}
                                                onChange={(e) => {
                                                    setNewPatientBirthDate(e.target.value);
                                                    calculateAge(e.target.value);
                                                }}
                                                className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                            />
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Idade (anos)</label>
                                        <input 
                                            type="number"
                                            value={newPatientAge}
                                            onChange={(e) => setNewPatientAge(e.target.value)}
                                            className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                            placeholder="Ex: 35"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Altura (cm)</label>
                                        <div className="relative">
                                            <input 
                                                type="number"
                                                value={newPatientHeight}
                                                onChange={(e) => setNewPatientHeight(e.target.value)}
                                                className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                                placeholder="Ex: 175"
                                            />
                                            <Ruler className="absolute right-2 top-2.5 h-4 w-4 text-slate-400 pointer-events-none" />
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Peso (kg)</label>
                                        <div className="relative">
                                            <input 
                                                type="number"
                                                value={newPatientWeight}
                                                onChange={(e) => setNewPatientWeight(e.target.value)}
                                                className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                                placeholder="Ex: 70"
                                            />
                                            <Weight className="absolute right-2 top-2.5 h-4 w-4 text-slate-400 pointer-events-none" />
                                        </div>
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-xs font-medium text-slate-500 mb-1">Contexto / Anamnese Detalhada (Histórico, diagnósticos, medicação)</label>
                                    <div className="h-48">
                                        <RichTextEditor 
                                            value={newPatientContext}
                                            onChange={setNewPatientContext}
                                            placeholder="Ex: Histórico familiar de depressão, uso de medicação contínua..."
                                            minHeight="min-h-[180px]"
                                        />
                                    </div>
                                </div>
                            </div>
                            <div className="flex justify-end gap-2">
                                <button 
                                    onClick={() => setIsCreatingPatient(false)}
                                    className="px-3 py-1.5 text-xs font-medium text-slate-600 hover:text-slate-800 border border-slate-300 rounded-md bg-white"
                                >
                                    Cancelar
                                </button>
                                <button 
                                    onClick={handleCreatePatient}
                                    disabled={!newPatientName.trim()}
                                    className="px-3 py-1.5 text-xs font-medium bg-teal-600 text-white rounded-md hover:bg-teal-700 disabled:opacity-50"
                                >
                                    Salvar Paciente
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="relative mt-1">
                            <select
                                value={currentPatient?.id || ''}
                                onChange={(e) => {
                                    const p = patients.find(pat => pat.id === e.target.value);
                                    setCurrentPatient(p || null);
                                }}
                                className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-800 focus:ring-1 focus:ring-teal-500 outline-none"
                            >
                                <option value="">Selecione um paciente (Opcional)...</option>
                                {patients.map(p => (
                                    <option key={p.id} value={p.id}>{p.name}</option>
                                ))}
                            </select>
                            {currentPatient && (
                                <div className="mt-4 bg-white p-4 rounded-lg border border-slate-200 shadow-sm">
                                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4 border-b border-slate-100 pb-4">
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Idade</span>
                                            <span className="text-sm font-medium text-slate-700 flex items-center gap-1">
                                                <Calculator className="h-3 w-3 text-teal-500" /> 
                                                {currentPatient.age ? `${currentPatient.age} anos` : '-'}
                                            </span>
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Nascimento</span>
                                            <span className="text-sm font-medium text-slate-700 flex items-center gap-1">
                                                <CalendarIcon className="h-3 w-3 text-teal-500" />
                                                {currentPatient.birthDate ? new Date(currentPatient.birthDate).toLocaleDateString('pt-BR', { timeZone: 'UTC' }) : '-'}
                                            </span>
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Altura</span>
                                            <span className="text-sm font-medium text-slate-700 flex items-center gap-1">
                                                <Ruler className="h-3 w-3 text-teal-500" />
                                                {currentPatient.height ? `${currentPatient.height} cm` : '-'}
                                            </span>
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Peso</span>
                                            <span className="text-sm font-medium text-slate-700 flex items-center gap-1">
                                                <Weight className="h-3 w-3 text-teal-500" />
