// Configuração da API do WhatsApp (Meta)
// EM PRODUÇÃO: Estas chaves devem estar em variáveis de ambiente e a chamada
// idealmente deve ser feita através de um backend próprio para não expor o token.
const WHATSAPP_API_TOKEN = process.env.REACT_APP_WHATSAPP_TOKEN || ''; 
const WHATSAPP_PHONE_ID = process.env.REACT_APP_WHATSAPP_PHONE_ID || '';
const WHATSAPP_VERSION = 'v17.0';

interface WhatsappResponse {
  messaging_product: string;
  contacts: { input: string; wa_id: string }[];
  messages: { id: string }[];
}

export const whatsappService = {
  /**
   * Envia um lembrete de agendamento usando um Template do WhatsApp Business.
   * Requer que o template 'appointment_reminder' esteja criado e aprovado no painel da Meta.
   */
  sendAppointmentReminder: async (
    phone: string, 
    patientName: string, 
    date: string, 
    time: string
  ): Promise<boolean> => {

    // Limpeza do telefone (apenas números)
    const cleanPhone = phone.replace(/\D/g, '');
    const formattedPhone = cleanPhone.length <= 11 ? `55${cleanPhone}` : cleanPhone;

    // Se não houver credenciais configuradas, SIMULA o envio (para testes de UI)
    if (!WHATSAPP_API_TOKEN || !WHATSAPP_PHONE_ID) {
      console.warn('⚠️ Credenciais da API do WhatsApp não encontradas.');
      console.group('🔔 [MOCK] Envio via WhatsApp API Oficial');
      console.log(`To: ${formattedPhone}`);
      console.log(`Payload: Template "appointment_reminder"`);
      console.log(`Params: ${patientName}, ${date}, ${time}`);
      console.groupEnd();

      // Simula delay de rede
      await new Promise(resolve => setTimeout(resolve, 1500));
      return true;
    }

    const url = `https://graph.facebook.com/${WHATSAPP_VERSION}/${WHATSAPP_PHONE_ID}/messages`;

    // Estrutura do payload para Template Message
    // Assumindo um template chamado "appointment_reminder" com 3 variáveis: {{1}}=Nome, {{2}}=Data, {{3}}=Hora
    const body = {
      messaging_product: 'whatsapp',
      to: formattedPhone,
      type: 'template',
      template: {
        name: 'appointment_reminder', 
        language: {
          code: 'pt_BR'
        },
        components: [
          {
            type: 'body',
            parameters: [
              { type: 'text', text: patientName }, // {{1}}
              { type: 'text', text: date },        // {{2}}
              { type: 'text', text: time }         // {{3}}
            ]
          }
        ]
      }
    };

    try {
      const response = await fetch(url, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${WHATSAPP_API_TOKEN}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(body)
      });

      if (!response.ok) {
        const errorData = await response.json();
        console.error('Erro WhatsApp API:', errorData);
        throw new Error(errorData.error?.message || 'Falha no envio');
      }

      const data: WhatsappResponse = await response.json();
      console.log('Sucesso WhatsApp API:', data);
      return true;

    } catch (error) {
      console.error('Erro ao enviar mensagem:', error);
      return false;
    }
  }
};

