  const [sessions, setSessions] = useState<ScheduledSession[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Estado para controlar qual sessão está enviando mensagem no momento
  const [sendingSessionId, setSendingSessionId] = useState<string | null>(null);

  // Form State
  const [selectedPatientId, setSelectedPatientId] = useState('');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [duration, setDuration] = useState(50);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = () => {
    setPatients(storageService.getPatients());
    // Sort sessions: Upcoming first, then by date/time
    const loadedSessions = storageService.getScheduledSessions().sort((a, b) => {
      const dateA = new Date(`${a.date}T${a.time}`);
      const dateB = new Date(`${b.date}T${b.time}`);
      return dateA.getTime() - dateB.getTime();
    });
    setSessions(loadedSessions);
  };

  const handleSave = () => {
    if (!selectedPatientId || !date || !time) return;

    const newSession: ScheduledSession = {
      id: Date.now().toString(),
      patientId: selectedPatientId,
      date,
      time,
      duration,
      status: 'scheduled',
      reminderSent: false // Initialize reminder status
    };

    storageService.saveScheduledSession(newSession);
    loadData();
    setIsModalOpen(false);
    resetForm();
