export default ScheduledSessions;

import React, { useState, useEffect } from 'react';
import { Patient, ScheduledSession } from '../types';
import { storageService } from '../services/storageService';
import { whatsappService } from '../services/whatsappService';
import { Calendar, Clock, Plus, CheckCircle, XCircle, Trash2, User, Play, X, MessageCircle, Loader2, Check } from 'lucide-react';

interface ScheduledSessionsProps {
  onStartSession: (patientId: string) => void;
}

const ScheduledSessions: React.FC<ScheduledSessionsProps> = ({ onStartSession }) => {
  const [sessions, setSessions] = useState<ScheduledSession[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Estado para controlar qual sessão está enviando mensagem no momento
  const [sendingSessionId, setSendingSessionId] = useState<string | null>(null);

  // Form State
  const [selectedPatientId, setSelectedPatientId] = useState('');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [duration, setDuration] = useState(50);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = () => {
    setPatients(storageService.getPatients());
    // Sort sessions: Upcoming first, then by date/time
    const loadedSessions = storageService.getScheduledSessions().sort((a, b) => {
      const dateA = new Date(`${a.date}T${a.time}`);
      const dateB = new Date(`${b.date}T${b.time}`);
      return dateA.getTime() - dateB.getTime();
    });
    setSessions(loadedSessions);
  };

  const handleSave = () => {
    if (!selectedPatientId || !date || !time) return;

    const newSession: ScheduledSession = {
      id: Date.now().toString(),
      patientId: selectedPatientId,
      date,
      time,
      duration,
      status: 'scheduled',
      reminderSent: false // Initialize reminder status
    };

    storageService.saveScheduledSession(newSession);
    loadData();
    setIsModalOpen(false);
    resetForm();
  };

  const resetForm = () => {
    setSelectedPatientId('');
    setDate('');
    setTime('');
    setDuration(50);
  };

  const updateStatus = (id: string, status: ScheduledSession['status']) => {
    storageService.updateScheduledSessionStatus(id, status);
    loadData();
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Cancelar este agendamento?')) {
      storageService.deleteScheduledSession(id);
      loadData();
    }
  };

  const getPatient = (id: string) => {
      return patients.find(p => p.id === id);
  };

  const getPatientName = (id: string) => {
    return getPatient(id)?.name || 'Paciente Desconhecido';
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'bg-green-100 text-green-800 border-green-200';
      case 'cancelled': return 'bg-red-100 text-red-800 border-red-200';
      default: return 'bg-white text-slate-800 border-slate-200';
    }
  };

  const filterSessions = (status: string) => {
      return sessions.filter(s => {
          if (status === 'upcoming') return s.status === 'scheduled';
          return s.status === status;
      });
  };

  const handleSendReminder = async (session: ScheduledSession) => {
      const patient = getPatient(session.patientId);

      if (!patient || !patient.phoneNumber) {
          alert("Este paciente não possui número de WhatsApp cadastrado.");
          return;
      }

      setSendingSessionId(session.id);

      try {
          const dateStr = new Date(session.date).toLocaleDateString('pt-BR');
          const success = await whatsappService.sendAppointmentReminder(
              patient.phoneNumber,
              patient.name,
              dateStr,
              session.time
          );

          if (success) {
              storageService.updateScheduledSessionReminder(session.id, true);
              loadData();
              // Opcional: Mostrar um toast de sucesso
          } else {
              alert("Falha ao enviar mensagem. Verifique o console para mais detalhes ou se as credenciais da API estão configuradas.");
          }
      } catch (error) {
          console.error(error);
          alert("Erro inesperado ao conectar com o serviço de mensagens.");
      } finally {
          setSendingSessionId(null);
      }
  };

  return (
    <div className="h-full flex flex-col">
      {/* Header / Actions */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
           <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
             <Calendar className="h-6 w-6 text-teal-600" />
             Agenda
           </h2>
           <p className="text-sm text-slate-500">Gerencie seus próximos atendimentos.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
