  };

  const getPatientName = (id: string) => {
    return getPatient(id)?.name || 'Paciente Desconhecido';
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'bg-green-100 text-green-800 border-green-200';
      case 'cancelled': return 'bg-red-100 text-red-800 border-red-200';
      default: return 'bg-white text-slate-800 border-slate-200';
    }
  };

  const filterSessions = (status: string) => {
      return sessions.filter(s => {
          if (status === 'upcoming') return s.status === 'scheduled';
          return s.status === status;
      });
  };

  // Envio via API (Pago/Simulado)
  const handleSendApiReminder = async (session: ScheduledSession) => {
      const patient = getPatient(session.patientId);

      if (!patient || !patient.phoneNumber) {
          alert("Este paciente não possui número de WhatsApp cadastrado.");
          return;
      }

      setSendingSessionId(session.id);

      try {
          const dateStr = new Date(session.date).toLocaleDateString('pt-BR');
          const success = await whatsappService.sendAppointmentReminder(
              patient.phoneNumber,
              patient.name,
              dateStr,
              session.time
          );

          if (success) {
              const now = new Date().toISOString();
              storageService.updateScheduledSessionReminder(session.id, true, now);
              loadData();
          } else {
              alert("Falha ao enviar mensagem via API.");
          }
      } catch (error) {
          console.error(error);
          alert("Erro inesperado ao conectar com o serviço de mensagens.");
      } finally {
          setSendingSessionId(null);
          setActiveMenuSessionId(null);
      }
  };

  // Envio Manual (Link wa.me - Gratuito)
  const handleManualWhatsApp = (session: ScheduledSession, type: 'confirm' | 'cancel') => {
      const patient = getPatient(session.patientId);

      if (!patient || !patient.phoneNumber) {
          alert("Este paciente não possui número de WhatsApp cadastrado.");
          return;
      }

      // Limpar telefone
      const cleanPhone = patient.phoneNumber.replace(/\D/g, '');
      const phone = cleanPhone.length <= 11 ? `55${cleanPhone}` : cleanPhone;

      const dateStr = new Date(session.date).toLocaleDateString('pt-BR');

      let message = '';
      if (type === 'confirm') {
          message = `Olá ${patient.name}, gostaria de confirmar nossa sessão agendada para *${dateStr} às ${session.time}*.`;
      } else {
          message = `Olá ${patient.name}, infelizmente precisarei remarcar nossa sessão de *${dateStr} às ${session.time}*. Podemos ver um novo horário?`;
      }

      const url = `https://wa.me/${phone}?text=${encodeURIComponent(message)}`;
      window.open(url, '_blank');
      setActiveMenuSessionId(null);
  };

  const formatReminderDate = (isoString?: string) => {
      if (!isoString) return 'Data desconhecida';
      return new Date(isoString).toLocaleString('pt-BR', {
          day: '2-digit',
          month: '2-digit',
          year: '2-digit',
          hour: '2-digit',
          minute: '2-digit'
      });
  };

  return (
    <div className="h-full flex flex-col">
      {/* Header / Actions */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
           <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
             <Calendar className="h-6 w-6 text-teal-600" />
             Agenda
           </h2>
           <p className="text-sm text-slate-500">Gerencie seus próximos atendimentos.</p>
        </div>
        <button 
          onClick={() => {
            resetForm();
            setIsModalOpen(true);
          }}
          className="bg-teal-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-teal-700 transition-colors flex items-center gap-2 shadow-sm"
        >
          <Plus className="h-4 w-4" /> Novo Agendamento
        </button>
      </div>

      {/* Lists */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Scheduled / Upcoming */}
        <div className="lg:col-span-2 space-y-4">
            <h3 className="font-semibold text-slate-700 flex items-center gap-2 border-b border-slate-200 pb-2">
                <Clock className="h-4 w-4 text-teal-600" /> Próximas Sessões
            </h3>

            {filterSessions('upcoming').length === 0 ? (
                <div className="bg-slate-50 border border-dashed border-slate-200 rounded-lg p-8 text-center text-slate-400">
                    Nenhuma sessão agendada.
                </div>
            ) : (
                <div className="grid gap-3">
                    {filterSessions('upcoming').map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-4 transition-all hover:shadow-md relative">
                            <div className="flex items-start gap-3 flex-1 min-w-0">
                                <div className="bg-teal-50 p-2.5 rounded-full mt-1 flex-shrink-0">
                                    <User className="h-5 w-5 text-teal-600" />
                                </div>
                                <div className="min-w-0 w-full">
                                    <h4 className="font-bold text-slate-800 truncate">{getPatientName(session.patientId)}</h4>
                                    <div className="flex items-center gap-3 text-sm text-slate-500 mt-1">
                                        <span className="flex items-center gap-1">
                                            <Calendar className="h-3.5 w-3.5" /> 
                                            {new Date(session.date).toLocaleDateString()}
                                        </span>
                                        <span className="flex items-center gap-1">
                                            <Clock className="h-3.5 w-3.5" /> 
                                            {session.time} ({session.duration} min)
                                        </span>
                                    </div>

                                    {session.notes && (
                                        <div className="mt-2 text-xs text-slate-600 bg-slate-50 p-2 rounded border border-slate-100 flex items-start gap-1.5 w-full md:w-[90%]">
                                            <FileText className="h-3.5 w-3.5 mt-0.5 text-slate-400 flex-shrink-0" />
                                            <span className="italic leading-relaxed break-words">{session.notes}</span>
                                        </div>
                                    )}

                                    {session.reminderSent && (
                                        <div className="flex items-center gap-1 mt-2 group relative w-fit cursor-help">
                                            <span className="text-[10px] text-green-600 bg-green-50 px-1.5 py-0.5 rounded border border-green-100 flex items-center gap-1">
                                                <CheckCircle className="h-3 w-3" /> Lembrete enviado
                                            </span>
                                            <Info className="h-3 w-3 text-slate-400 hover:text-slate-600" />

                                            {/* Tooltip */}
                                            <div className="absolute left-0 bottom-full mb-1 hidden group-hover:block z-50">
                                                <div className="bg-slate-800 text-white text-[10px] py-1 px-2 rounded shadow-lg whitespace-nowrap">
                                                    Enviado em: {formatReminderDate(session.reminderSentAt)}
                                                    <div className="absolute top-full left-4 -ml-1 border-4 border-transparent border-t-slate-800"></div>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>

                            <div className="flex items-center gap-2 w-full md:w-auto mt-2 md:mt-0 flex-shrink-0">
                                {/* WhatsApp Button with Dropdown */}
                                <div className="relative" onClick={(e) => e.stopPropagation()}>
                                    <button 
                                        onClick={() => setActiveMenuSessionId(activeMenuSessionId === session.id ? null : session.id)}
                                        disabled={sendingSessionId === session.id}
                                        className={`p-1.5 border rounded transition-colors ${
                                            session.reminderSent || activeMenuSessionId === session.id
                                            ? 'text-green-600 border-green-200 bg-green-50' 
                                            : 'text-slate-400 hover:text-green-600 border-slate-200 hover:bg-green-50'
                                        }`}
                                        title="Opções de Mensagem"
                                    >
                                        {sendingSessionId === session.id ? (
                                            <Loader2 className="h-4 w-4 animate-spin" />
                                        ) : (
                                            <MessageCircle className="h-4 w-4" />
                                        )}
                                    </button>

                                    {/* Dropdown Menu */}
                                    {activeMenuSessionId === session.id && (
                                        <div className="absolute right-0 top-full mt-2 w-64 bg-white rounded-lg shadow-xl border border-slate-100 z-50 animate-fadeIn">
                                            <div className="py-1">
                                                <div className="px-3 py-2 border-b border-slate-50 bg-slate-50/50">
                                                     <p className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Ações Manuais (Grátis)</p>
                                                </div>
                                                <button
                                                    onClick={() => handleManualWhatsApp(session, 'confirm')}
                                                    className="w-full text-left px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                                                >
                                                    <Smartphone className="h-4 w-4 text-green-500" /> Confirmar Consulta
                                                </button>
                                                <button
                                                    onClick={() => handleManualWhatsApp(session, 'cancel')}
                                                    className="w-full text-left px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                                                >
                                                    <XCircle className="h-4 w-4 text-orange-500" /> Desmarcar/Remarcar
                                                </button>

                                                <div className="border-t border-slate-100 my-1"></div>
                                                <div className="px-3 py-1 bg-slate-50/50">
                                                     <p className="text-[10px] text-slate-400">Automação (Requer API)</p>
                                                </div>
                                                <button
                                                    onClick={() => handleSendApiReminder(session)}
                                                    className="w-full text-left px-4 py-2 text-sm text-slate-600 hover:bg-slate-50 flex items-center gap-2"
                                                >
                                                    <Zap className="h-4 w-4 text-yellow-500" /> Lembrete Automático
                                                </button>
                                            </div>
                                        </div>
                                    )}
                                </div>

                                <button 
                                    onClick={() => handleEdit(session)}
                                    className="p-1.5 text-slate-400 hover:text-blue-600 border border-slate-200 rounded hover:bg-blue-50 transition-colors"
                                    title="Editar Agendamento"
                                >
                                    <Edit2 className="h-4 w-4" />
                                </button>

                                <button 
                                    onClick={() => updateStatus(session.id, 'completed')}
                                    className="p-1.5 text-slate-400 hover:text-teal-600 border border-slate-200 rounded hover:bg-teal-50 transition-colors"
                                    title="Marcar como Realizada (Sem Iniciar)"
                                >
                                    <Check className="h-4 w-4" />
                                </button>

                                <button 
                                    onClick={() => {
                                        updateStatus(session.id, 'completed');
                                        onStartSession(session.patientId);
                                    }}
                                    className="flex-1 md:flex-none flex items-center justify-center gap-1 bg-teal-600 text-white px-3 py-1.5 rounded-md text-xs font-medium hover:bg-teal-700 transition-colors"
                                    title="Iniciar Atendimento"
                                >
                                    <Play className="h-3 w-3" /> Iniciar
                                </button>
                                <button 
                                    onClick={() => updateStatus(session.id, 'cancelled')}
                                    className="p-1.5 text-slate-400 hover:text-red-500 border border-slate-200 rounded hover:bg-red-50 transition-colors"
                                    title="Cancelar"
                                >
                                    <XCircle className="h-4 w-4" />
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>

        {/* Recent History (Completed/Cancelled) */}
        <div className="space-y-4">
             <h3 className="font-semibold text-slate-700 flex items-center gap-2 border-b border-slate-200 pb-2">
                <Calendar className="h-4 w-4 text-slate-400" /> Recentes
            </h3>
            <div className="space-y-2">
                {sessions.filter(s => s.status !== 'scheduled').sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 10).map(session => (
                    <div key={session.id} className={`p-3 rounded-lg border text-sm flex justify-between items-center ${getStatusColor(session.status)}`}>
                        <div className="min-w-0">
                            <p className="font-medium truncate">{getPatientName(session.patientId)}</p>
                            <p className="text-xs opacity-80">{new Date(session.date).toLocaleDateString()} às {session.time}</p>
                            {session.notes && (
                                <p className="text-[10px] mt-1 text-slate-500 italic truncate max-w-[200px]">
                                    {session.notes}
                                </p>
                            )}
                        </div>
                        <div className="flex items-center gap-2 flex-shrink-0">
                            <span className="text-[10px] uppercase font-bold tracking-wider px-1.5 py-0.5 rounded bg-white/50">
                                {session.status === 'completed' ? 'Realizada' : 'Cancelada'}
                            </span>
                            <button onClick={() => handleDelete(session.id)} className="text-slate-400 hover:text-red-600">
                                <Trash2 className="h-3.5 w-3.5" />
                            </button>
                        </div>
                    </div>
                ))}
                {sessions.filter(s => s.status !== 'scheduled').length === 0 && (
                    <p className="text-xs text-slate-400 italic text-center py-4">Nenhum histórico recente.</p>
                )}
            </div>
        </div>

      </div>

      {/* Modal Create/Edit */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
           <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm" onClick={handleCloseModal}></div>
           <div className="bg-white rounded-xl shadow-xl w-full max-w-md z-10 overflow-hidden animate-fadeIn flex flex-col max-h-[90vh]">
              <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 flex-shrink-0">
                  <h3 className="font-bold text-slate-800">
                      {editingSessionId ? 'Editar Agendamento' : 'Novo Agendamento'}
                  </h3>
                  <button onClick={handleCloseModal} className="text-slate-400 hover:text-slate-600"><X className="h-5 w-5"/></button>
              </div>
              <div className="p-6 space-y-4 overflow-y-auto">
                  <div>
                      <label className="block text-xs font-medium text-slate-600 mb-1">Paciente</label>
                      <select 
                        value={selectedPatientId} 
                        onChange={(e) => setSelectedPatientId(e.target.value)}
                        className="w-full p-2.5 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                      >
                          <option value="">Selecione...</option>
                          {patients.map(p => (
                              <option key={p.id} value={p.id}>{p.name}</option>
                          ))}
                      </select>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                      <div>
                          <label className="block text-xs font-medium text-slate-600 mb-1">Data</label>
                          <input 
                            type="date" 
                            value={date}
                            onChange={(e) => setDate(e.target.value)}
                            className="w-full p-2.5 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                          />
                      </div>
                      <div>
                          <label className="block text-xs font-medium text-slate-600 mb-1">Horário</label>
                          <input 
                            type="time" 
                            value={time}
                            onChange={(e) => setTime(e.target.value)}
                            className="w-full p-2.5 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                          />
                      </div>
                  </div>
                  <div>
                      <label className="block text-xs font-medium text-slate-600 mb-1">Duração (minutos)</label>
                      <input 
                        type="number" 
                        value={duration}
                        onChange={(e) => setDuration(Number(e.target.value))}
                        className="w-full p-2.5 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                      />
                  </div>

                  <div>
                      <label className="block text-xs font-medium text-slate-600 mb-1">Observações (Opcional)</label>
                      <textarea
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        className="w-full p-2.5 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none h-20"
                        placeholder="Ex: Trazer relatório escolar, focar em ansiedade..."
                      />
                  </div>

                  <button 
                    onClick={handleSave}
                    disabled={!selectedPatientId || !date || !time}
                    className="w-full mt-4 bg-teal-600 text-white py-2.5 rounded-lg font-medium hover:bg-teal-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex-shrink-0"
                  >
                      {editingSessionId ? 'Salvar Alterações' : 'Confirmar Agendamento'}
                  </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default ScheduledSessions;

import React, { useState, useEffect } from 'react';
import { Patient, SessionRecord } from '../types';
import { storageService } from '../services/storageService';
import { User, Calendar, MessageCircle, Clock, AlertCircle, TrendingUp } from 'lucide-react';

interface InactivePatient extends Patient {
  lastSessionDate: Date | null;
  daysAbsent: number;
}

const Remarketing: React.FC = () => {
  const [inactivePatients, setInactivePatients] = useState<InactivePatient[]>([]);
  const [thresholdDays, setThresholdDays] = useState(30);

  useEffect(() => {
    analyzePatients();
  }, [thresholdDays]);

  const analyzePatients = () => {
    const patients = storageService.getPatients();
    const now = new Date();
    const results: InactivePatient[] = [];

    patients.forEach(patient => {
      const sessions = storageService.getSessionsByPatient(patient.id);

      let lastSessionDate: Date | null = null;
      let daysAbsent = 0;

      if (sessions.length > 0) {
        // As sessões já vêm ordenadas da mais recente para a mais antiga no storageService
        lastSessionDate = new Date(sessions[0].date);
        const diffTime = Math.abs(now.getTime() - lastSessionDate.getTime());
        daysAbsent = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      } else {
        // Se nunca teve sessão, conta desde a criação do cadastro
        const createdDate = new Date(patient.createdAt || new Date().toISOString());
        const diffTime = Math.abs(now.getTime() - createdDate.getTime());
        daysAbsent = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      }

      // Filtra baseado no limite de dias (ex: mais de 30 dias sem vir)
      if (daysAbsent >= thresholdDays) {
        results.push({
          ...patient,
          lastSessionDate,
          daysAbsent
        });
      }
    });

    // Ordenar: Quem está ausente há mais tempo primeiro (mas talvez quem nunca veio seja prioridade)
    // Vamos ordenar por dias ausentes (decrescente)
    results.sort((a, b) => b.daysAbsent - a.daysAbsent);
    setInactivePatients(results);
  };

  const handleWhatsAppContact = (patient: InactivePatient) => {
    if (!patient.phoneNumber) {
      alert("Este paciente não possui número cadastrado.");
      return;
    }

    const cleanPhone = patient.phoneNumber.replace(/\D/g, '');
    const phone = cleanPhone.length <= 11 ? `55${cleanPhone}` : cleanPhone;

    let message = '';

    if (patient.lastSessionDate) {
      // Mensagem para retorno (já é paciente antigo)
      message = `Olá ${patient.name}, tudo bem? Notei que faz um tempinho desde nossa última sessão. Como você tem estado? Estou organizando a agenda e gostaria de saber se deseja retomar nossos encontros.`;
    } else {
      // Mensagem para quem cadastrou mas nunca fez sessão (Lead)
      message = `Olá ${patient.name}, tudo bem? Vi aqui que realizamos seu cadastro mas ainda não iniciamos as sessões. Gostaria de verificar sua disponibilidade para agendarmos um horário?`;
    }

    const url = `https://wa.me/${phone}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">

      {/* Header */}
      <div className="p-6 border-b border-slate-200 bg-slate-50 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <TrendingUp className="h-6 w-6 text-orange-500" />
            Remarketing & Recuperação
          </h2>
          <p className="text-sm text-slate-500">
            Pacientes que não realizam sessões há mais de {thresholdDays} dias.
          </p>
        </div>

        <div className="flex items-center gap-2 bg-white p-2 rounded-lg border border-slate-200">
           <span className="text-xs font-medium text-slate-600">Filtrar ausência:</span>
           <select 
              value={thresholdDays}
              onChange={(e) => setThresholdDays(Number(e.target.value))}
              className="text-sm border-none bg-transparent font-bold text-teal-700 focus:ring-0 cursor-pointer outline-none"
           >
              <option value={15}>&gt; 15 dias</option>
              <option value={30}>&gt; 30 dias</option>
              <option value={60}>&gt; 60 dias</option>
              <option value={90}>&gt; 90 dias</option>
           </select>
        </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 bg-slate-50/50">
        {inactivePatients.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-slate-400">
             <AlertCircle className="h-12 w-12 mb-3 opacity-20" />
             <p>Nenhum paciente inativo encontrado para este período.</p>
             <p className="text-xs">Sua retenção de pacientes está ótima!</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {inactivePatients.map(patient => (
              <div key={patient.id} className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all group">

                <div className="flex justify-between items-start mb-3">
                   <div className="flex items-center gap-3">
                      <div className={`p-2 rounded-full ${patient.lastSessionDate ? 'bg-orange-50 text-orange-600' : 'bg-blue-50 text-blue-600'}`}>
                        <User className="h-5 w-5" />
                      </div>
                      <div>
                        <h3 className="font-bold text-slate-800 truncate max-w-[150px]">{patient.name}</h3>
                        <p className="text-xs text-slate-500 flex items-center gap-1">
                           {patient.lastSessionDate ? 'Paciente Inativo' : 'Nunca iniciou'}
                        </p>
                      </div>
                   </div>
                   <div className="text-right">
                      <span className="block text-2xl font-bold text-slate-700">{patient.daysAbsent}</span>
                      <span className="text-[10px] text-slate-400 uppercase tracking-wider font-medium">Dias s/ Sessão</span>
                   </div>
                </div>

                <div className="space-y-2 mb-4">
                    <div className="flex items-center gap-2 text-xs text-slate-600 bg-slate-50 p-2 rounded">
                        <Calendar className="h-3.5 w-3.5 text-slate-400" />
                        <span>
                            Última vez: {patient.lastSessionDate ? patient.lastSessionDate.toLocaleDateString() : 'Nunca'}
                        </span>
                    </div>
                    {patient.phoneNumber ? (
                       <div className="flex items-center gap-2 text-xs text-slate-600 bg-slate-50 p-2 rounded">
                          <MessageCircle className="h-3.5 w-3.5 text-green-600" />
                          <span>{patient.phoneNumber}</span>
                       </div>
                    ) : (
                       <div className="flex items-center gap-2 text-xs text-red-500 bg-red-50 p-2 rounded">
                          <AlertCircle className="h-3.5 w-3.5" />
                          <span>Sem telefone cadastrado</span>
                       </div>
                    )}
                </div>

                <button
                  onClick={() => handleWhatsAppContact(patient)}
                  disabled={!patient.phoneNumber}
                  className="w-full flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700 text-white py-2.5 rounded-lg text-sm font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                >
                  <MessageCircle className="h-4 w-4" />
                  Mandar Mensagem
                </button>

                <p className="text-[10px] text-center text-slate-400 mt-2">
                   Abre o WhatsApp com mensagem sugerida
                </p>

              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Remarketing;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
import ReportView from './components/ReportView';
import TemplateManager from './components/TemplateManager';
import PatientHistory from './components/PatientHistory';
import ScheduledSessions from './components/ScheduledSessions';
import Remarketing from './components/Remarketing';
import RichTextEditor from './components/RichTextEditor';
import { analyzeSessionNotes } from './services/geminiService';
import { storageService } from './services/storageService';
import { notificationService } from './services/notificationService';
import { AnalysisRequest, ReportTemplate, Patient, SessionRecord } from './types';
import { Plus, Users, History, Save, Calculator, Calendar as CalendarIcon, Ruler, Weight, CalendarCheck, Phone, TrendingUp } from 'lucide-react';

// Default Templates
const DEFAULT_TEMPLATES: ReportTemplate[] = [
  {
    id: 'default-1',
    name: 'Padrão (Evolução Clínica)',
    isDefault: true,
    structure: `# Evolução Clínica

## 1. Resumo da Sessão
Síntese dos temas abordados e acontecimentos principais.

## 2. Análise do Estado Emocional
Humor predominante, afeto e congruência.

## 3. Conteúdos Relevantes (Abordagem Específica)
Interpretação dos dados à luz da teoria selecionada.

## 4. Intervenções Realizadas
Técnicas aplicadas, manejo clínico e psicoeducação.

## 5. Planejamento Terapêutico
Encaminhamentos e foco para próximos atendimentos.`
  },
  {
    id: 'default-integrativo',
    name: 'Integrativo (Holístico)',
    isDefault: true,
    structure: `# Relatório Integrativo

## Dimensão Mental & Cognitiva
Padrões de pensamento, crenças e narrativa trazida.

## Dimensão Emocional
Sentimentos identificados, expressão e regulação emocional.

## Dimensão Somática & Energética
Queixas físicas, linguagem corporal, nível de energia/disposição.

## Contexto Sistêmico & Relacional
Dinâmicas familiares, sociais e ambientais impactando o quadro.

## Síntese Integrativa
Como as dimensões acima se conectam na queixa atual.

## Práticas e Recomendações
Sugestões terapêuticas, exercícios ou florais/recursos complementares (se aplicável à abordagem).`
  },
  {
    id: 'default-exame',
    name: 'Exame das Funções Mentais (MSE)',
    isDefault: true,
    structure: `# Súmula do Exame Psíquico

## Apresentação Geral
Aparência, higiene, postura e atitude frente ao examinador.

## Consciência e Atenção
Nível de vigilância, tenacidade e mobilidade da atenção.

## Orientação e Memória
Orientação alopsíquica/autopsíquica e memória (imediata/recente/remota).

## Sensopercepção e Pensamento
Curso, forma e conteúdo do pensamento; presença de alucinações/ilusões.

## Afetividade e Humor
Modulação afetiva e estado de humor basal.

## Juízo Crítico e Conduta
Insight sobre o adoecimento e controle de impulsos.`
  },
  {
    id: 'default-soap',
    name: 'SOAP (Hospitalar/Convênio)',
    isDefault: true,
    structure: `# Registro SOAP

## S - Subjetivo (Subjective)
Relato do paciente (ipsis litteris quando relevante). Queixa principal.

## O - Objetivo (Objective)
Observações clínicas do terapeuta. Exame do estado mental breve.

## A - Avaliação (Assessment)
Análise do progresso, hipóteses diagnósticas e mudanças sintomáticas.

## P - Plano (Plan)
Conduta, ajustes no tratamento, tarefas de casa e agendamento.`
  }
];

type Tab = 'new' | 'history' | 'schedule' | 'remarketing';

function App() {
  const [activeTab, setActiveTab] = useState<Tab>('new');
  const [report, setReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Patient State
  const [patients, setPatients] = useState<Patient[]>([]);
  const [currentPatient, setCurrentPatient] = useState<Patient | null>(null);
  const [isCreatingPatient, setIsCreatingPatient] = useState(false);

  // New Patient Form State
  const [newPatientName, setNewPatientName] = useState('');
  const [newPatientPhone, setNewPatientPhone] = useState('');
  const [newPatientBirthDate, setNewPatientBirthDate] = useState('');
  const [newPatientAge, setNewPatientAge] = useState('');
  const [newPatientHeight, setNewPatientHeight] = useState('');
  const [newPatientWeight, setNewPatientWeight] = useState('');
  const [newPatientContext, setNewPatientContext] = useState('');

  // Template State
  const [templates, setTemplates] = useState<ReportTemplate[]>(DEFAULT_TEMPLATES);
  const [selectedTemplateId, setSelectedTemplateId] = useState<string>(DEFAULT_TEMPLATES[0].id);
  const [isTemplateManagerOpen, setIsTemplateManagerOpen] = useState(false);

  useEffect(() => {
    refreshPatients();

    // Check for reminders immediately on load
    notificationService.checkAndSendReminders();

    // Check every minute
    const interval = setInterval(() => {
        notificationService.checkAndSendReminders();
    }, 60000);

    return () => clearInterval(interval);
  }, []);

  const refreshPatients = () => {
    setPatients(storageService.getPatients());
  };

  const calculateAge = (dob: string) => {
    if (!dob) return;
    const birthDate = new Date(dob);
    const today = new Date();
    let age = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
      age--;
    }
    setNewPatientAge(age.toString());
  };

  const handleCreatePatient = () => {
    if (!newPatientName.trim()) return;

    const newPatient: Patient = {
        id: Date.now().toString(),
        name: newPatientName,
        phoneNumber: newPatientPhone,
        birthDate: newPatientBirthDate,
        age: newPatientAge,
        height: newPatientHeight,
        weight: newPatientWeight,
        context: newPatientContext,
        createdAt: new Date().toISOString()
    };

    storageService.savePatient(newPatient);
    refreshPatients();
    setCurrentPatient(newPatient);
    setIsCreatingPatient(false);

    // Reset form
    setNewPatientName('');
    setNewPatientPhone('');
    setNewPatientBirthDate('');
    setNewPatientAge('');
    setNewPatientHeight('');
    setNewPatientWeight('');
    setNewPatientContext('');
  };

  const handleAnalysis = async (notes: string, approach: string) => {
    const selectedTemplate = templates.find(t => t.id === selectedTemplateId) || DEFAULT_TEMPLATES[0];

    setIsAnalyzing(true);
    setReport(null); 

    // Construct a rich context string including demographics
    let fullContext = currentPatient?.context || "";
    if (currentPatient) {
        const demos = [];
        if (currentPatient.age) demos.push(`Idade: ${currentPatient.age} anos`);
        if (currentPatient.birthDate) demos.push(`Data de Nasc.: ${new Date(currentPatient.birthDate).toLocaleDateString('pt-BR')}`);
        if (currentPatient.height) demos.push(`Altura: ${currentPatient.height}cm`);
        if (currentPatient.weight) demos.push(`Peso: ${currentPatient.weight}kg`);

        if (demos.length > 0) {
            fullContext = `DADOS DEMOGRÁFICOS:\n${demos.join(' | ')}\n\nCONTEXTO CLÍNICO:\n${fullContext}`;
        }
    }

    const request: AnalysisRequest = {
      notes,
      approach,
      patientContext: fullContext,
      templateStructure: selectedTemplate.structure
    };

    const result = await analyzeSessionNotes(request);
    setReport(result);
    setIsAnalyzing(false);

    // Auto-save session if patient is selected
    if (currentPatient && result) {
        const newSession: SessionRecord = {
            id: Date.now().toString(),
            patientId: currentPatient.id,
            date: new Date().toISOString(),
            rawNotes: notes,
            generatedReport: result,
            approach,
            templateName: selectedTemplate.name
        };
        storageService.saveSession(newSession);
    }
  };

  const handleStartScheduledSession = (patientId: string) => {
      const patient = patients.find(p => p.id === patientId);
      if (patient) {
          setCurrentPatient(patient);
          setActiveTab('new');
      }
  };

  const handleAddTemplate = (newTemplate: ReportTemplate) => {
    setTemplates([...templates, newTemplate]);
    setSelectedTemplateId(newTemplate.id);
    setIsTemplateManagerOpen(false);
  };

  const handleDeleteTemplate = (id: string) => {
    const newTemplates = templates.filter(t => t.id !== id);
    setTemplates(newTemplates);
    if (selectedTemplateId === id) {
        setSelectedTemplateId(newTemplates[0].id);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <Header />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-4 md:py-8">

        {/* Navigation Tabs */}
        <div className="flex items-center space-x-4 mb-6 border-b border-slate-200 overflow-x-auto">
            <button
                onClick={() => setActiveTab('new')}
                className={`pb-3 px-1 flex items-center gap-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${activeTab === 'new' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
                <Plus className="h-4 w-4" /> Nova Sessão
            </button>
            <button
                onClick={() => setActiveTab('schedule')}
                className={`pb-3 px-1 flex items-center gap-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${activeTab === 'schedule' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
                <CalendarCheck className="h-4 w-4" /> Sessões Agendadas
            </button>
            <button
                onClick={() => setActiveTab('history')}
                className={`pb-3 px-1 flex items-center gap-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${activeTab === 'history' ? 'border-teal-600 text-teal-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
                <History className="h-4 w-4" /> Histórico
            </button>
            <button
                onClick={() => setActiveTab('remarketing')}
                className={`pb-3 px-1 flex items-center gap-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${activeTab === 'remarketing' ? 'border-orange-500 text-orange-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
                <TrendingUp className="h-4 w-4" /> Remarketing
            </button>
        </div>

        {activeTab === 'new' && (
            <>
                {/* Patient Selection Section */}
                <div className="mb-6 bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="flex flex-wrap items-center justify-between mb-2 gap-2">
                        <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
                            <Users className="h-4 w-4 text-teal-600" />
                            Paciente
                        </label>
                        {!isCreatingPatient && (
                            <button 
                                onClick={() => setIsCreatingPatient(true)}
                                className="text-xs text-teal-600 font-bold hover:text-teal-800 uppercase tracking-wide flex items-center gap-1 bg-teal-50 px-2 py-1 rounded"
                            >
                                <Plus className="h-3 w-3" /> Novo Paciente
                            </button>
                        )}
                    </div>

                    {isCreatingPatient ? (
                        <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 animate-fadeIn mt-2">
                            <div className="space-y-4 mb-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Nome Completo *</label>
                                        <input 
                                            type="text"
                                            value={newPatientName}
                                            onChange={(e) => setNewPatientName(e.target.value)}
                                            className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                            placeholder="Nome do paciente"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">WhatsApp / Telefone</label>
                                        <input 
                                            type="text"
                                            value={newPatientPhone}
                                            onChange={(e) => setNewPatientPhone(e.target.value)}
                                            className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                            placeholder="Ex: 11 99999-9999"
                                        />
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Data de Nascimento</label>
                                        <div className="relative">
                                            <input 
                                                type="date"
                                                value={newPatientBirthDate}
                                                onChange={(e) => {
                                                    setNewPatientBirthDate(e.target.value);
                                                    calculateAge(e.target.value);
                                                }}
                                                className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                            />
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Idade (anos)</label>
                                        <input 
                                            type="number"
                                            value={newPatientAge}
                                            onChange={(e) => setNewPatientAge(e.target.value)}
                                            className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                            placeholder="Ex: 35"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Altura (cm)</label>
                                        <div className="relative">
                                            <input 
                                                type="number"
                                                value={newPatientHeight}
                                                onChange={(e) => setNewPatientHeight(e.target.value)}
                                                className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                                placeholder="Ex: 175"
                                            />
                                            <Ruler className="absolute right-2 top-2.5 h-4 w-4 text-slate-400 pointer-events-none" />
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Peso (kg)</label>
                                        <div className="relative">
                                            <input 
                                                type="number"
                                                value={newPatientWeight}
                                                onChange={(e) => setNewPatientWeight(e.target.value)}
                                                className="w-full text-sm p-2 border border-slate-300 rounded-md focus:ring-1 focus:ring-teal-500"
                                                placeholder="Ex: 70"
                                            />
                                            <Weight className="absolute right-2 top-2.5 h-4 w-4 text-slate-400 pointer-events-none" />
                                        </div>
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-xs font-medium text-slate-500 mb-1">Contexto / Anamnese Detalhada (Histórico, diagnósticos, medicação)</label>
                                    <div className="h-48">
                                        <RichTextEditor 
                                            value={newPatientContext}
                                            onChange={setNewPatientContext}
                                            placeholder="Ex: Histórico familiar de depressão, uso de medicação contínua..."
                                            minHeight="min-h-[180px]"
                                        />
                                    </div>
                                </div>
                            </div>
                            <div className="flex justify-end gap-2">
                                <button 
                                    onClick={() => setIsCreatingPatient(false)}
                                    className="px-3 py-1.5 text-xs font-medium text-slate-600 hover:text-slate-800 border border-slate-300 rounded-md bg-white"
                                >
                                    Cancelar
                                </button>
                                <button 
                                    onClick={handleCreatePatient}
                                    disabled={!newPatientName.trim()}
                                    className="px-3 py-1.5 text-xs font-medium bg-teal-600 text-white rounded-md hover:bg-teal-700 disabled:opacity-50"
                                >
                                    Salvar Paciente
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="relative mt-1">
                            <select
                                value={currentPatient?.id || ''}
                                onChange={(e) => {
                                    const p = patients.find(pat => pat.id === e.target.value);
                                    setCurrentPatient(p || null);
                                }}
                                className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-800 focus:ring-1 focus:ring-teal-500 outline-none"
                            >
                                <option value="">Selecione um paciente (Opcional)...</option>
                                {patients.map(p => (
                                    <option key={p.id} value={p.id}>{p.name}</option>
                                ))}
                            </select>
                            {currentPatient && (
                                <div className="mt-4 bg-white p-4 rounded-lg border border-slate-200 shadow-sm">
                                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4 border-b border-slate-100 pb-4">
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Idade</span>
                                            <span className="text-sm font-medium text-slate-700 flex items-center gap-1">
                                                <Calculator className="h-3 w-3 text-teal-500" /> 
                                                {currentPatient.age ? `${currentPatient.age} anos` : '-'}
                                            </span>
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Nascimento</span>
                                            <span className="text-sm font-medium text-slate-700 flex items-center gap-1">
                                                <CalendarIcon className="h-3 w-3 text-teal-500" />
                                                {currentPatient.birthDate ? new Date(currentPatient.birthDate).toLocaleDateString('pt-BR', { timeZone: 'UTC' }) : '-'}
                                            </span>
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Altura</span>
                                            <span className="text-sm font-medium text-slate-700 flex items-center gap-1">
                                                <Ruler className="h-3 w-3 text-teal-500" />
                                                {currentPatient.height ? `${currentPatient.height} cm` : '-'}
                                            </span>
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Peso</span>
                                            <span className="text-sm font-medium text-slate-700 flex items-center gap-1">
                                                <Weight className="h-3 w-3 text-teal-500" />
                                                {currentPatient.weight ? `${currentPatient.weight} kg` : '-'}
                                            </span>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2 mb-2">
                                        {currentPatient.phoneNumber && (
                                            <span className="text-xs bg-green-50 text-green-700 px-2 py-1 rounded border border-green-100 flex items-center gap-1">
                                                <Phone className="h-3 w-3" /> {currentPatient.phoneNumber}
                                            </span>
                                        )}
                                    </div>
                                    <span className="text-xs font-bold text-slate-600 block mb-1 uppercase tracking-wide">Contexto Clínico:</span>
                                    <div 
                                        className="prose prose-sm max-w-none text-xs text-slate-500 leading-relaxed bg-slate-50 p-2 rounded"
                                        dangerouslySetInnerHTML={{ __html: currentPatient.context || "<p class='italic'>Sem contexto definido.</p>" }}
                                    />
                                </div>
                            )}
                        </div>
                    )}
                </div>

                {/* Main Content Grid - Changed to Flex Col for Mobile/Tablet, Grid for Large Desktop */}
                <div className="flex flex-col lg:grid lg:grid-cols-2 gap-8 lg:h-[calc(100vh-280px)] h-auto">
                    {/* Left Column: Input */}
                    <div className="flex flex-col gap-4 h-full order-1">
                        <InputForm 
                            onSubmit={handleAnalysis} 
                            isAnalyzing={isAnalyzing} 
                            templates={templates}
                            selectedTemplateId={selectedTemplateId}
                            onSelectTemplate={setSelectedTemplateId}
                            onOpenTemplateManager={() => setIsTemplateManagerOpen(true)}
                        />
                    </div>

                    {/* Right Column: Output */}
                    <div className="h-full min-h-[500px] lg:min-h-0 relative order-2">
                        <ReportView report={report} />
                        {report && currentPatient && !isAnalyzing && (
                            <div className="absolute top-4 right-4 md:right-20 bg-teal-100 text-teal-800 text-xs px-2 py-1 rounded-md flex items-center gap-1 animate-pulse shadow-sm z-10">
                                <Save className="h-3 w-3" /> <span className="hidden sm:inline">Salvo no Histórico</span> <span className="sm:hidden">Salvo</span>
                            </div>
                        )}
                        {report && !currentPatient && !isAnalyzing && (
                            <div className="absolute top-4 right-4 md:right-20 bg-yellow-100 text-yellow-800 text-xs px-2 py-1 rounded-md flex items-center gap-1 shadow-sm z-10">
                                <span className="hidden sm:inline">⚠️ Não salvo (Sem Paciente)</span> <span className="sm:hidden">⚠️ Não salvo</span>
                            </div>
                        )}
                    </div>
                </div>
            </>
        )}

        {activeTab === 'schedule' && (
            <ScheduledSessions onStartSession={handleStartScheduledSession} />
        )}

        {activeTab === 'history' && (
            <PatientHistory />
        )}

        {activeTab === 'remarketing' && (
            <Remarketing />
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-xs md:text-sm text-slate-500">
                &copy; {new Date().getFullYear()} PsiAI. Desenvolvido para Psicólogos e Terapeutas.
                <span className="block md:inline mx-0 md:mx-2 mt-1 md:mt-0 text-slate-300">|</span>
                <span className="text-slate-400 block md:inline">Dados armazenados localmente no seu dispositivo.</span>
            </p>
        </div>
      </footer>

      <TemplateManager 
        isOpen={isTemplateManagerOpen}
        onClose={() => setIsTemplateManagerOpen(false)}
        templates={templates}
        onAddTemplate={handleAddTemplate}
        onDeleteTemplate={handleDeleteTemplate}
      />
    </div>
  );
}

export default App;
